const WIKI_DATA = {"articles": [{"id": "brede-welvaart-concept", "title": "Brede welvaart: concept, meting en het BBP", "thema": "kwaliteit-van-leven", "cluster": "1. Concept en meting", "meta": "Bronnen: CPB (5 documenten uit het beleidscorpus)", "sections": [{"type": "h2", "text": "Wat is brede welvaart?", "citations": []}, {"type": "p", "text": "Brede welvaart is een concept dat de kwaliteit van leven in bredere zin meet dan alleen het bruto binnenlands product (BBP). Het begrip vindt zijn oorsprong in de internationale Beyond GDP-discussie, die onder meer werd aangejaagd door de Stiglitz-Sen-Fitoussi-commissie in 2009. Sinds 2016 hanteren de planbureaus een gezamenlijke definitie: brede welvaart als de kwaliteit van leven hier en nu, en de effecten daarvan op latere generaties en op mensen in andere delen van de wereld.", "citations": [{"source_id": {"instituut": "PBL", "titel": "Brede welvaart in het onderzoek van het PBL", "jaar": "2016", "auteur": "Dietz, Hanemaaijer", "url": "https://www.pbl.nl/publicaties/brede-welvaart-in-het-onderzoek-van-het-pbl", "lokaal_pad": ""}, "page": 3}, {"source_id": {"instituut": "CPB", "titel": "Aspecten van brede welvaart in CPB-studies", "jaar": "2016", "auteur": "CPB", "url": "https://www.cpb.nl/publicatie/aspecten-van-brede-welvaart-in-cpb-studies", "lokaal_pad": ""}, "page": 5}]}, {"type": "p", "text": "Het concept kent drie tijdsdimensies die in samenhang worden beschouwd. De dimensie hier en nu omvat de huidige kwaliteit van leven: gezondheid, opleiding, inkomen, milieu en sociale omgeving. De dimensie later richt zich op de effecten van huidige keuzes op toekomstige generaties, zoals CO2-uitstoot, grondstoffengebruik en staatsschuld. De dimensie elders ten slotte betreft de effecten van Nederlandse keuzes op welvaart in andere landen, zoals de ecologische voetafdruk en handelsrelaties.", "citations": [{"source_id": {"instituut": "PBL", "titel": "Brede welvaart in elke regio", "jaar": "2024", "auteur": "Weterings e.a.", "url": "https://www.pbl.nl/publicaties/brede-welvaart-in-elke-regio", "lokaal_pad": ""}, "page": 5}, {"source_id": {"instituut": "CPB", "titel": "Aspecten van brede welvaart in CPB-studies", "jaar": "2016", "auteur": "CPB", "url": "https://www.cpb.nl/publicatie/aspecten-van-brede-welvaart-in-cpb-studies", "lokaal_pad": ""}, "page": 8}]}, {"type": "h2", "text": "Brede welvaart versus BBP", "citations": []}, {"type": "p", "text": "Het BBP meet de totale waarde van geproduceerde goederen en diensten, maar zegt niets over hoe welvaart is verdeeld, over de staat van het milieu, of over de kwaliteit van sociale verbanden. Het SCP benadrukt dat de kwaliteit van de samenleving een eigenstandige waarde heeft die niet terug te voeren is op economische indicatoren alleen. De WRR pleit in dit verband voor een kwalitatieve benadering van economische ontwikkeling die verder kijkt dan louter productiegroei.", "citations": [{"source_id": {"instituut": "SCP", "titel": "Brede welvaart en kwaliteit van de samenleving", "jaar": "2024", "auteur": "SCP", "url": "https://www.scp.nl/documenten/2024/02/28/brede-welvaart-en-kwaliteit-van-de-samenleving", "lokaal_pad": ""}, "page": 5}, {"source_id": {"instituut": "WRR", "titel": "Theorieën van de onderneming - brede welvaart", "jaar": "2022", "auteur": "WRR", "url": "https://www.wrr.nl/documenten/2022/03/15/theorieen-van-de-onderneming", "lokaal_pad": ""}, "page": 6}]}, {"type": "h2", "text": "Hoe meten we brede welvaart?", "citations": []}, {"type": "p", "text": "Het CBS publiceert sinds 2018 jaarlijks de Monitor Brede Welvaart, met tientallen indicatoren verdeeld over de drie dimensies. De drie planbureaus hebben daarnaast een Kernset Indicatoren Brede Welvaart ontwikkeld waarmee beleidseffecten systematisch kunnen worden gemeten. Een belangrijke uitdaging is echter dat niet alles wat van waarde is, meetbaar is, en dat de weging van indicatoren onvermijdelijk normatief is.", "citations": [{"source_id": {"instituut": "CBS", "titel": "Monitor Brede Welvaart & SDG's", "jaar": "2024", "auteur": "CBS", "url": "https://www.cbs.nl/nl-nl/dossier/dossier-brede-welvaart-en-de-sustainable-development-goals", "lokaal_pad": ""}, "page": 3}, {"source_id": {"instituut": "SCP", "titel": "Verankering van brede welvaart in begrotingssystematiek", "jaar": "2022", "auteur": "SCP, PBL, CPB", "url": "https://www.scp.nl/documenten/2022/06/30/verankering-van-brede-welvaart-in-de-begrotingssystematiek", "lokaal_pad": ""}, "page": 3}, {"source_id": {"instituut": "WRR", "titel": "Theorieën van de onderneming - brede welvaart", "jaar": "2022", "auteur": "WRR", "url": "https://www.wrr.nl/documenten/2022/03/15/theorieen-van-de-onderneming", "lokaal_pad": ""}, "page": 8}]}, {"type": "p", "text": "In 2022 deed het PBL specifiek onderzoek naar de gemeentelijke verdeling van brede welvaart. De verschillen tussen gemeenten blijken groot en beleidsrelevant. Dit sluit aan bij het advies [[regionale-brede-welvaart:Elke regio telt!]], dat oproept tot een nieuwe aanpak van regionale verschillen.", "citations": [{"source_id": {"instituut": "PBL", "titel": "Brede welvaart in Nederlandse gemeenten", "jaar": "2022", "auteur": "PBL", "url": "https://www.pbl.nl/publicaties/brede-welvaart-in-nederlandse-gemeenten-het-belang-van-regionale-samenhang", "lokaal_pad": ""}, "page": 4}, {"source_id": {"instituut": "PBL", "titel": "Brede welvaart in elke regio", "jaar": "2024", "auteur": "Weterings e.a.", "url": "https://www.pbl.nl/publicaties/brede-welvaart-in-elke-regio", "lokaal_pad": ""}, "page": 10}]}], "see_also": ["regionale-brede-welvaart", "bestaanszekerheid-sociaal", "circulair-klimaat"], "tags": ["Brede welvaart", "Concept", "Meten", "BBP", "PBL", "CPB", "SCP", "CBS"]}, {"id": "regionale-brede-welvaart", "title": "Regionale brede welvaart: van advies naar beleid", "thema": "kwaliteit-van-leven", "cluster": "2. Regionale brede welvaart", "meta": "Bronnen: CPB, PBL (5 documenten uit het beleidscorpus)", "sections": [{"type": "h2", "text": "Het advies Elke regio telt!", "citations": []}, {"type": "p", "text": "In maart 2023 brachten de Raad voor de leefomgeving en infrastructuur (RLI), de Raad voor het openbaar bestuur (ROB) en de Raad voor de volksgezondheid en samenleving (RVS) het gezamenlijke advies Elke regio telt! uit. De drie raden stellen daarin dat nationaal beleid in de afgelopen decennia heeft bijgedragen aan de toenemende regionale verschillen in Nederland. Zij roepen het Rijk op om de beleidsfocus te verleggen naar een toekomst met brede welvaart in elke regio.", "citations": [{"source_id": {"instituut": "RLI", "titel": "Elke regio telt!", "jaar": "2023", "auteur": "RLI, ROB & RVS", "url": "https://www.rli.nl/publicaties/2023/advies/elke-regio-telt", "lokaal_pad": ""}, "page": 5}]}, {"type": "p", "text": "In juli 2023 reageerde het demissionaire kabinet Rutte-IV positief op het advies. Het PBL kreeg vervolgens de opdracht om de politieke keuzes in kaart te brengen die nodig zijn om regionale brede welvaart te realiseren. Dit resulteerde in 2024 in de publicatie Brede welvaart in elke regio, waarin drie fundamentele opvattingen over een rechtvaardige verdeling van welvaart over regio's worden onderscheiden.", "citations": [{"source_id": {"instituut": "ROB", "titel": "Kabinetsreactie op advies Elke regio telt!", "jaar": "2023", "auteur": "ROB", "url": "https://www.raadopenbaarbestuur.nl/documenten/2023/7/12/kabinetsreactie-elke-regio-telt", "lokaal_pad": ""}, "page": 2}, {"source_id": {"instituut": "PBL", "titel": "Brede welvaart in elke regio", "jaar": "2024", "auteur": "Weterings e.a.", "url": "https://www.pbl.nl/publicaties/brede-welvaart-in-elke-regio", "lokaal_pad": ""}, "page": 4}]}, {"type": "h2", "text": "Drie opvattingen over regionale verdeling", "citations": []}, {"type": "p", "text": "De eerste opvatting is het maximaliseren van nationale welvaart: inzetten op sterke regio's levert het meeste op voor Nederland als geheel. De tweede is het verminderen van verschillen tussen regio's: actief beleid om regionale ongelijkheid te verkleinen. De derde is het garanderen van voldoende welvaart in elke regio: een minimumnorm ongeacht hoe andere regio's presteren. Elk van deze opvattingen heeft andere gevolgen voor beleid.", "citations": [{"source_id": {"instituut": "PBL", "titel": "Brede welvaart in elke regio", "jaar": "2024", "auteur": "Weterings e.a.", "url": "https://www.pbl.nl/publicaties/brede-welvaart-in-elke-regio", "lokaal_pad": ""}, "page": 11}]}, {"type": "h2", "text": "Regio Deals als instrument", "citations": []}, {"type": "p", "text": "Sinds 2018 zet het kabinet Regio Deals in als instrument om regionale brede welvaart te bevorderen. Het PBL-onderzoeksprogramma liep van 2019 tot 2021. Het PBL-onderzoeksprogramma (2019-2021) laat zien dat het effect op brede welvaart afhangt van heldere doelstellingen, integrale aanpak en goede monitoring. De SER adviseert daarnaast over regionale samenwerkingsverbanden en hun effectiviteit voor brede welvaart.", "citations": [{"source_id": {"instituut": "PBL", "titel": "Regio Deals voor de brede welvaart", "jaar": "2020", "auteur": "PBL", "url": "https://www.pbl.nl/publicaties/pbl-onderzoeksprogramma-regio-deals-voor-de-brede-welvaart-2019-2021", "lokaal_pad": ""}, "page": 3}, {"source_id": {"instituut": "SER", "titel": "Regionaal samenwerken: leren van praktijken", "jaar": "2017", "auteur": "SER", "url": "https://www.ser.nl/nl/publicaties/regionaal-samenwerken", "lokaal_pad": ""}, "page": 4}]}, {"type": "h2", "text": "Provinciale toepassing", "citations": []}, {"type": "p", "text": "De provincie Utrecht heeft [[brede-welvaart-concept:brede welvaart]] als centraal thema opgenomen in haar strategische kennisagenda 2026-2027. Dit betekent dat provinciaal beleid — van ruimtelijke ordening en mobiliteit tot wonen en natuur — wordt getoetst aan bredewelvaartscriteria. De ROB benadrukt dat dit vraagt om aanpassingen in bestuurlijke structuren en financiële verhoudingen tussen Rijk, provincies en gemeenten.", "citations": [{"source_id": {"instituut": "ROB", "titel": "Lef en evenwicht - financiële verhoudingen", "jaar": "2024", "auteur": "ROB", "url": "https://www.raadopenbaarbestuur.nl/documenten/2024/02/29/briefadvies-raamwerk-toekomstbestendige-financiele-verhoudingen", "lokaal_pad": ""}, "page": 3}, {"source_id": {"instituut": "ROB", "titel": "Brede welvaart, grote opgaven", "jaar": "2022", "auteur": "ROB", "url": "https://www.raadopenbaarbestuur.nl/documenten/2022/04/12/brede-welvaart-grote-opgaven", "lokaal_pad": ""}, "page": 6}]}], "see_also": ["brede-welvaart-concept", "bestaanszekerheid-sociaal"], "tags": ["Regionaal", "RLI", "ROB", "PBL", "Regio Deals", "Provincie", "Utrecht"]}, {"id": "bestaanszekerheid-sociaal", "title": "Bestaanszekerheid en sociale kwaliteit", "thema": "kwaliteit-van-leven", "cluster": "3. Bestaanszekerheid en sociale kwaliteit", "meta": "Bronnen: CPB, PBL, SCP (5 documenten uit het beleidscorpus)", "sections": [{"type": "h2", "text": "Bestaanszekerheid en brede welvaart", "citations": []}, {"type": "p", "text": "Bestaanszekerheid gaat over de mate waarin mensen kunnen rekenen op een stabiel en voorspelbaar bestaan: voldoende inkomen, goed werk, betaalbare huisvesting, toegang tot zorg en onderwijs, en sociale zekerheid. In 2025 onderzocht het SCP hoe bestaanszekerheid zich verhoudt tot het bredere concept brede welvaart. Waar bestaanszekerheid zich traditioneel richt op economische zekerheid, voegt een bredewelvaartsperspectief dimensies toe als gezondheid, mentaal welzijn, vertrouwen in instituties en kwaliteit van de leefomgeving.", "citations": [{"source_id": {"instituut": "SCP", "titel": "Bestaanszekerheid vanuit bredewelvaartsperspectief", "jaar": "2025", "auteur": "SCP", "url": "https://www.scp.nl/documenten/2025/08/28/bestaanszekerheid-vanuit-een-bredewelvaartsperspectief", "lokaal_pad": ""}, "page": 3}, {"source_id": {"instituut": "SCP", "titel": "Bestaanszekerheid vanuit bredewelvaartsperspectief", "jaar": "2025", "auteur": "SCP", "url": "https://www.scp.nl/documenten/2025/08/28/bestaanszekerheid-vanuit-een-bredewelvaartsperspectief", "lokaal_pad": ""}, "page": 5}]}, {"type": "h2", "text": "Kwaliteit van de samenleving", "citations": []}, {"type": "p", "text": "Het SCP definieert de kwaliteit van de samenleving aan de hand van vier pijlers: sociale cohesie (verbondenheid tussen mensen, onderling vertrouwen), maatschappelijke betrokkenheid (vrijwilligerswerk, verenigingsleven, burgerparticipatie), vertrouwen in instituties (overheid, politiek, rechtspraak, media) en ervaren kwaliteit van leven (tevredenheid met wonen, werk, vrije tijd en sociale contacten). Deze factoren worden in de [[brede-welvaart-concept:Monitor Brede Welvaart]] van het CBS meegenomen als indicatoren voor sociale kwaliteit.", "citations": [{"source_id": {"instituut": "SCP", "titel": "Brede welvaart en kwaliteit van de samenleving", "jaar": "2024", "auteur": "SCP", "url": "https://www.scp.nl/documenten/2024/02/28/brede-welvaart-en-kwaliteit-van-de-samenleving", "lokaal_pad": ""}, "page": 3}, {"source_id": {"instituut": "SCP", "titel": "Brede welvaart en kwaliteit van de samenleving", "jaar": "2024", "auteur": "SCP", "url": "https://www.scp.nl/documenten/2024/02/28/brede-welvaart-en-kwaliteit-van-de-samenleving", "lokaal_pad": ""}, "page": 5}]}, {"type": "p", "text": "Het SCP verbindt deze abstracte concepten aan meetbare indicatoren die direct bruikbaar zijn voor beleid. De WRR onderzocht daarnaast de wisselwerking tussen brede welvaart en institutioneel vertrouwen, en concludeert dat vertrouwen in instituties een voorwaarde is voor effectief beleid.", "citations": [{"source_id": {"instituut": "WRR", "titel": "Theorieën van de onderneming - brede welvaart", "jaar": "2022", "auteur": "WRR", "url": "https://www.wrr.nl/documenten/2022/03/15/theorieen-van-de-onderneming", "lokaal_pad": ""}, "page": 6}]}, {"type": "h2", "text": "Burgerperspectieven en maatschappelijk onbehagen", "citations": []}, {"type": "p", "text": "Wat vinden burgers zelf van waarde? Het SCP brengt via de Burgerperspectieven Berichten periodiek in kaart wat er leeft in de samenleving. In februari 2026 was brede welvaart het centrale thema van het Burgerperspectieven Bericht. Belangrijke inzichten zijn dat burgers veel waarde hechten aan zaken die moeilijk in cijfers te vangen zijn — rust, ruimte, sociale contacten, veiligheid — en dat er significante variatie bestaat tussen regio's in wat mensen als een goed leven beschouwen.", "citations": [{"source_id": {"instituut": "SCP", "titel": "Burgerperspectieven Bericht 1 2026 - Thema Brede Welvaart", "jaar": "2026", "auteur": "SCP", "url": "https://www.scp.nl/documenten/2026/02/05/burgerperspectieven-bericht-1-2026-thema-brede-welvaart", "lokaal_pad": ""}, "page": 3}, {"source_id": {"instituut": "SCP", "titel": "Burgerperspectieven Bericht 1 2026 - Thema Brede Welvaart", "jaar": "2026", "auteur": "SCP", "url": "https://www.scp.nl/documenten/2026/02/05/burgerperspectieven-bericht-1-2026-thema-brede-welvaart", "lokaal_pad": ""}, "page": 6}]}, {"type": "p", "text": "Tegelijkertijd constateert het SCP dat gevoelens van maatschappelijk onbehagen en wantrouwen toenemen. Eenzaamheid is een groeiend probleem, met name onder ouderen. Vrijwilligerswerk en mantelzorg staan onder druk door individualisering en tijdsdruk. Dit alles beïnvloedt de ervaren brede welvaart en vraagt om een integrale beleidsaanpak.", "citations": [{"source_id": {"instituut": "SCP", "titel": "Burgerperspectieven Bericht 3 2025 - Maatschappelijk onbehagen", "jaar": "2025", "auteur": "SCP", "url": "https://www.scp.nl/documenten/2025/10/20/burgerperspectieven-2025-bericht-3", "lokaal_pad": ""}, "page": 4}, {"source_id": {"instituut": "SCP", "titel": "De sociale staat van Nederland 2017", "jaar": "2017", "auteur": "SCP", "url": "https://repository.scp.nl/?atabase=9eb0bac7-6d6f-490e-b252-789aef5aeca7", "lokaal_pad": ""}, "page": 5}, {"source_id": {"instituut": "SCP", "titel": "Brede welvaart en kwaliteit van de samenleving", "jaar": "2024", "auteur": "SCP", "url": "https://www.scp.nl/documenten/2024/02/28/brede-welvaart-en-kwaliteit-van-de-samenleving", "lokaal_pad": ""}, "page": 6}]}], "see_also": ["sociaaleconomisch", "sociale-ongelijkheid"], "tags": ["Bestaanszekerheid", "SCP", "Sociale kwaliteit", "Burgerperspectieven", "Eenzaamheid"]}, {"id": "sociaaleconomisch", "title": "Sociaaleconomisch beleid, inkomen en arbeid", "thema": "kwaliteit-van-leven", "cluster": "4. Sociaaleconomisch beleid", "meta": "Bronnen: CPB (5 documenten uit het beleidscorpus)", "sections": [{"type": "h2", "text": "Inkomen en arbeid in bredewelvaartsperspectief", "citations": []}, {"type": "p", "text": "Inkomen is een belangrijk middel om welvaart te realiseren, maar is niet hetzelfde als welvaart. Het CPB benadrukt dat inkomensgroei alleen bijdraagt aan brede welvaart als deze gepaard gaat met behoud van gezondheid, milieu en sociale cohesie. Werk draagt niet alleen bij aan inkomen maar ook aan zingeving, sociale contacten en persoonlijke ontwikkeling.", "citations": [{"source_id": {"instituut": "CPB", "titel": "Aspecten van brede welvaart in CPB-studies", "jaar": "2016", "auteur": "CPB", "url": "https://www.cpb.nl/publicatie/aspecten-van-brede-welvaart-in-cpb-studies", "lokaal_pad": ""}, "page": 3}, {"source_id": {"instituut": "CPB", "titel": "Aspecten van brede welvaart in CPB-studies", "jaar": "2016", "auteur": "CPB", "url": "https://www.cpb.nl/publicatie/aspecten-van-brede-welvaart-in-cpb-studies", "lokaal_pad": ""}, "page": 4}]}, {"type": "p", "text": "De arbeidsmarkt verandert echter snel. Het CPB signaleerde in 2015 dat baanpolarisatie optreedt: banen in het middensegment verdwijnen, terwijl zowel laag- als hoogopgeleid werk groeit. Tegelijkertijd neemt de flexibilisering van de arbeid toe, wat voor sommigen kansen biedt maar voor anderen leidt tot onzekerheid over inkomen en arbeidsvoorwaarden.", "citations": [{"source_id": {"instituut": "CPB", "titel": "Baanpolarisatie in Nederland", "jaar": "2015", "auteur": "CPB", "url": "https://www.cpb.nl/publicatie/baanpolarisatie-in-nederland", "lokaal_pad": ""}, "page": 3}, {"source_id": {"instituut": "CPB", "titel": "De ontwikkeling van flexibele arbeid", "jaar": "2016", "auteur": "CPB", "url": "https://www.cpb.nl/publicatie/de-ontwikkeling-van-flexibele-arbeid-een-sectoraal-perspectief", "lokaal_pad": ""}, "page": 5}]}, {"type": "h2", "text": "Sociaaleconomisch beleid", "citations": []}, {"type": "p", "text": "In 2021 adviseerde de SER over de samenhang tussen economische groei, arbeidsparticipatie en sociale zekerheid. Vanuit [[brede-welvaart-concept:bredewelvaartsperspectief]] is het van belang dat economisch beleid niet alleen op productiviteit is gericht, maar ook op kwaliteit van werk en werk-privébalans. Het PBL voegt hieraan toe dat sociaaleconomisch beleid in brede zin ook oog moet hebben voor de effecten op gezondheid, sociale cohesie en milieu.", "citations": [{"source_id": {"instituut": "SER", "titel": "Advies over sociaal-economisch beleid 2021-2025", "jaar": "2021", "auteur": "SER", "url": "https://www.ser.nl/nl/publicaties/sociaal-economisch-beleid-2021-2025", "lokaal_pad": ""}, "page": 5}, {"source_id": {"instituut": "PBL", "titel": "Sociaal-economisch beleid vanuit bredewelvaartsperspectief", "jaar": "2023", "auteur": "PBL & RUG", "url": "https://www.pbl.nl/publicaties/sociaal-economisch-beleid-vanuit-een-bredewelvaartsperspectief", "lokaal_pad": ""}, "page": 3}]}, {"type": "h2", "text": "Economische groei en haar grenzen", "citations": []}, {"type": "p", "text": "Economische groei is historisch de belangrijkste motor geweest voor welvaartsstijging, maar kent ecologische en sociale grenzen. Waar het BBP blind is voor milieuschade en ongelijkheid, dwingt een bredewelvaartsperspectief tot expliciete afwegingen. Het SCP benadrukt dat economisch beleid brede welvaart als uitgangspunt moet nemen, niet BBP-maximalisatie.", "citations": [{"source_id": {"instituut": "CPB", "titel": "Aspecten van brede welvaart in CPB-studies", "jaar": "2016", "auteur": "CPB", "url": "https://www.cpb.nl/publicatie/aspecten-van-brede-welvaart-in-cpb-studies", "lokaal_pad": ""}, "page": 10}, {"source_id": {"instituut": "SCP", "titel": "Brede welvaart en kwaliteit van de samenleving", "jaar": "2024", "auteur": "SCP", "url": "https://www.scp.nl/documenten/2024/02/28/brede-welvaart-en-kwaliteit-van-de-samenleving", "lokaal_pad": ""}, "page": 8}, {"source_id": {"instituut": "PBL", "titel": "Sociaal-economisch beleid vanuit bredewelvaartsperspectief", "jaar": "2023", "auteur": "PBL & RUG", "url": "https://www.pbl.nl/publicaties/sociaal-economisch-beleid-vanuit-een-bredewelvaartsperspectief", "lokaal_pad": ""}, "page": 5}]}], "see_also": ["sociale-ongelijkheid", "bestaanszekerheid-sociaal"], "tags": ["Sociaaleconomisch", "CPB", "SER", "Arbeid", "Inkomen", "Economische groei"]}, {"id": "sociale-ongelijkheid", "title": "Sociale ongelijkheid en intergenerationele rechtvaardigheid", "thema": "kwaliteit-van-leven", "cluster": "5. Sociale ongelijkheid en rechtvaardigheid", "meta": "Bronnen: CPB (5 documenten uit het beleidscorpus)", "sections": [{"type": "h2", "text": "Ongelijkheid in Nederland", "citations": []}, {"type": "p", "text": "Verschillen in inkomen, gezondheid, opleiding en participatie tussen bevolkingsgroepen zijn hardnekkig en in sommige opzichten groeiend. In 2014 publiceerde het SCP Verschil in Nederland, waaruit blijkt dat de tegenstellingen tussen groepen met een hoge en lage sociaaleconomische status toenemen, ook waar objectieve inkomensverschillen beperkt lijken.", "citations": [{"source_id": {"instituut": "SCP", "titel": "Verschil in Nederland 2014-2020", "jaar": "2014", "auteur": "SCP", "url": "https://www.scp.nl/documenten/2014/12/12/verschil-in-nederland-2014", "lokaal_pad": ""}, "page": 5}, {"source_id": {"instituut": "SCP", "titel": "Brede welvaart en kwaliteit van de samenleving", "jaar": "2024", "auteur": "SCP", "url": "https://www.scp.nl/documenten/2024/02/28/brede-welvaart-en-kwaliteit-van-de-samenleving", "lokaal_pad": ""}, "page": 7}]}, {"type": "h2", "text": "Intergenerationele rechtvaardigheid", "citations": []}, {"type": "p", "text": "Intergenerationele rechtvaardigheid gaat over de verdeling van welvaart en lasten tussen generaties. De WRR onderzocht in 2024 de gevolgen van Europese vergrijzing voor pensioenen en begrotingshoudbaarheid. Een krimpend arbeidsaanbod en stijgende zorgkosten leggen een steeds grotere claim op de welvaart van jongere generaties.", "citations": [{"source_id": {"instituut": "WRR", "titel": "Europese vergrijzing in het vizier", "jaar": "2024", "auteur": "WRR", "url": "https://www.wrr.nl/documenten/2024/09/25/europese-vergrijzing-in-het-vizier", "lokaal_pad": ""}, "page": 4}]}, {"type": "p", "text": "Het CPB analyseerde de effecten van vergrijzing op de economie en de houdbaarheid van het sociale stelsel. De combinatie van een oplopende staatsschuld, stijgende zorguitgaven en een krimpende beroepsbevolking vraagt om intergenerationele solidariteit: een eerlijke verdeling van lasten tussen werkenden en gepensioneerden, en tussen huidige en toekomstige belastingbetalers.", "citations": [{"source_id": {"instituut": "CPB", "titel": "Aspecten van brede welvaart in CPB-studies", "jaar": "2016", "auteur": "CPB", "url": "https://www.cpb.nl/publicatie/aspecten-van-brede-welvaart-in-cpb-studies", "lokaal_pad": ""}, "page": 8}, {"source_id": {"instituut": "WRR", "titel": "Europese vergrijzing in het vizier", "jaar": "2024", "auteur": "WRR", "url": "https://www.wrr.nl/documenten/2024/09/25/europese-vergrijzing-in-het-vizier", "lokaal_pad": ""}, "page": 5}]}, {"type": "h2", "text": "Ruimtelijke ongelijkheid", "citations": []}, {"type": "p", "text": "Ongelijkheid heeft ook een ruimtelijke dimensie. Binnen de provincie Utrecht zijn de verschillen tussen de stad Utrecht en omliggende kernen aanzienlijk, zoals beschreven in het advies [[regionale-brede-welvaart:Elke regio telt!]]. Het PBL brengt deze regionale verschillen systematisch in kaart op gemeentelijk niveau.", "citations": [{"source_id": {"instituut": "PBL", "titel": "Brede welvaart in Nederlandse gemeenten", "jaar": "2022", "auteur": "PBL", "url": "https://www.pbl.nl/publicaties/brede-welvaart-in-nederlandse-gemeenten-het-belang-van-regionale-samenhang", "lokaal_pad": ""}, "page": 4}, {"source_id": {"instituut": "RLI", "titel": "Elke regio telt!", "jaar": "2023", "auteur": "RLI, ROB & RVS", "url": "https://www.rli.nl/publicaties/2023/advies/elke-regio-telt", "lokaal_pad": ""}, "page": 6}]}], "see_also": ["sociaaleconomisch", "bestaanszekerheid-sociaal", "regionale-brede-welvaart"], "tags": ["Ongelijkheid", "Intergenerationeel", "SCP", "WRR", "CPB", "Rechtvaardigheid"]}, {"id": "gezondheid-natuur-milieu", "title": "Gezondheid, natuur en milieu", "thema": "kwaliteit-van-leven", "cluster": "6. Gezondheid, natuur en milieu", "meta": "Bronnen: CPB (5 documenten uit het beleidscorpus)", "sections": [{"type": "h2", "text": "Gezondheid en leefomgeving", "citations": []}, {"type": "p", "text": "Fysieke en mentale gezondheid zijn kerncomponenten van brede welvaart. Het RIVM bracht in 2015 de relatie tussen de leefomgeving en gezondheid in kaart: luchtkwaliteit, geluidshinder, toegang tot groen en beweegvriendelijkheid van de openbare ruimte zijn concrete factoren die de gezondheid beïnvloeden. Het SCP constateert tegelijkertijd dat gezondheidsverschillen tussen sociaaleconomische groepen groot zijn en bovendien toenemen.", "citations": [{"source_id": {"instituut": "RIVM", "titel": "Ruimte en gezondheid", "jaar": "2015", "auteur": "RIVM", "url": "https://www.rivm.nl/publicaties/ruimte-en-gezondheid-vanzelfsprekende-combinatie-verkenning-naar-relatie-tussen", "lokaal_pad": ""}, "page": 3}, {"source_id": {"instituut": "RIVM", "titel": "Ruimte en gezondheid", "jaar": "2015", "auteur": "RIVM", "url": "https://www.rivm.nl/publicaties/ruimte-en-gezondheid-vanzelfsprekende-combinatie-verkenning-naar-relatie-tussen", "lokaal_pad": ""}, "page": 5}, {"source_id": {"instituut": "SCP", "titel": "Verschil in Nederland 2014-2020", "jaar": "2014", "auteur": "SCP", "url": "https://www.scp.nl/documenten/2014/12/12/verschil-in-nederland-2014", "lokaal_pad": ""}, "page": 5}]}, {"type": "h2", "text": "Natuur en biodiversiteit", "citations": []}, {"type": "p", "text": "Een gezonde natuurlijke leefomgeving is een randvoorwaarde voor brede welvaart, nu en voor toekomstige generaties. Biodiversiteit is natuurlijk kapitaal dat bijdraagt aan productie, recreatie, waterzuivering en klimaatadaptatie. Het verlies aan biodiversiteit heeft directe effecten op de ecosysteemdiensten die de basis vormen voor onze welvaart.", "citations": [{"source_id": {"instituut": "PBL", "titel": "Brede welvaart in Nederlandse gemeenten", "jaar": "2022", "auteur": "PBL", "url": "https://www.pbl.nl/publicaties/brede-welvaart-in-nederlandse-gemeenten-het-belang-van-regionale-samenhang", "lokaal_pad": ""}, "page": 6}, {"source_id": {"instituut": "PBL", "titel": "Brede welvaart in elke regio", "jaar": "2024", "auteur": "Weterings e.a.", "url": "https://www.pbl.nl/publicaties/brede-welvaart-in-elke-regio", "lokaal_pad": ""}, "page": 15}]}, {"type": "h2", "text": "Milieu, water en bodem", "citations": []}, {"type": "p", "text": "Waterkwaliteit, bodemgezondheid en luchtkwaliteit zijn provinciale beleidsterreinen die direct raken aan brede welvaart. De stikstofproblematiek is een van de grootste provinciale opgaven en raakt aan vrijwel alle provinciale taken: natuur, landbouw, woningbouw en infrastructuur. Het RLI-advies [[regionale-brede-welvaart:Elke regio telt!]] besteedt hier uitgebreid aandacht aan.", "citations": [{"source_id": {"instituut": "RLI", "titel": "Elke regio telt!", "jaar": "2023", "auteur": "RLI, ROB & RVS", "url": "https://www.rli.nl/publicaties/2023/advies/elke-regio-telt", "lokaal_pad": ""}, "page": 8}, {"source_id": {"instituut": "RIVM", "titel": "Monitor Gezonde Leefomgeving", "jaar": "2020", "auteur": "RIVM", "url": "https://www.rivm.nl/publicaties/regios-in-beweging-naar-toekomstbestendig-gezondheidssysteem", "lokaal_pad": ""}, "page": 3}]}, {"type": "h2", "text": "Beleidsafwegingen", "citations": []}, {"type": "p", "text": "Het PBL waarschuwt dat economische groei gepaard gaat met milieudruk die de brede welvaart op termijn ondermijnt. Het SCP voegt hieraan toe dat natuur en milieu niet alleen een economische maar ook een sociale en culturele waarde hebben die in beleidsafwegingen moet worden meegewogen.", "citations": [{"source_id": {"instituut": "PBL", "titel": "Brede welvaart in het onderzoek van het PBL", "jaar": "2016", "auteur": "Dietz, Hanemaaijer", "url": "https://www.pbl.nl/publicaties/brede-welvaart-in-het-onderzoek-van-het-pbl", "lokaal_pad": ""}, "page": 8}, {"source_id": {"instituut": "SCP", "titel": "Brede welvaart en kwaliteit van de samenleving", "jaar": "2024", "auteur": "SCP", "url": "https://www.scp.nl/documenten/2024/02/28/brede-welvaart-en-kwaliteit-van-de-samenleving", "lokaal_pad": ""}, "page": 7}]}], "see_also": ["circulair-klimaat", "regionale-brede-welvaart", "sociale-ongelijkheid"], "tags": ["Gezondheid", "RIVM", "Natuur", "Biodiversiteit", "Milieu", "Stikstof", "PBL"]}, {"id": "wonen-mobiliteit", "title": "Wonen, mobiliteit en bereikbaarheid", "thema": "kwaliteit-van-leven", "cluster": "7. Wonen, mobiliteit en bereikbaarheid", "meta": "Bronnen: CPB (5 documenten uit het beleidscorpus)", "sections": [{"type": "h2", "text": "Wonen en brede welvaart", "citations": []}, {"type": "p", "text": "De kwaliteit, betaalbaarheid en locatie van woningen bepalen in belangrijke mate de kwaliteit van leven. Een krappe woningmarkt leidt tot hoge prijzen, langere reistijden en woononzekerheid — factoren die de brede welvaart negatief beïnvloeden. In 2022 onderzocht het PBL de samenhang tussen wonen en brede welvaart op gemeentelijk niveau.", "citations": [{"source_id": {"instituut": "PBL", "titel": "Brede welvaart in Nederlandse gemeenten", "jaar": "2022", "auteur": "PBL", "url": "https://www.pbl.nl/publicaties/brede-welvaart-in-nederlandse-gemeenten-het-belang-van-regionale-samenhang", "lokaal_pad": ""}, "page": 6}, {"source_id": {"instituut": "PBL", "titel": "Brede welvaart in elke regio", "jaar": "2024", "auteur": "Weterings e.a.", "url": "https://www.pbl.nl/publicaties/brede-welvaart-in-elke-regio", "lokaal_pad": ""}, "page": 22}]}, {"type": "p", "text": "Verstedelijking biedt economische kansen maar legt tegelijkertijd druk op de leefomgeving. De RLI adviseerde al in 2018 dat woningbouw gepaard moet gaan met investeringen in bereikbaarheid, voorzieningen en kwaliteit van de openbare ruimte. In de provincie Utrecht is de woningmarktdruk het grootst, wat jonge gezinnen naar andere provincies drijft.", "citations": [{"source_id": {"instituut": "RLI", "titel": "Versnellen woningbouw met behoud kwaliteit", "jaar": "2018", "auteur": "RLI", "url": "https://www.rli.nl/publicaties/2018/advies/versnellen-woningbouwproductie-met-behoud-van-kwaliteit", "lokaal_pad": ""}, "page": 3}, {"source_id": {"instituut": "PBL", "titel": "Nieuwe perspectieven voor groeikernen", "jaar": "2015", "auteur": "PBL", "url": "https://www.pbl.nl/publicaties/een-nieuw-perspectief-voor-oude-groeikernen", "lokaal_pad": ""}, "page": 4}]}, {"type": "h2", "text": "Mobiliteit en bereikbaarheid", "citations": []}, {"type": "p", "text": "Mobiliteit raakt aan vrijwel alle aspecten van brede welvaart: bereikbaarheid van werk en voorzieningen, gezondheid (luchtkwaliteit, beweging), sociale contacten en leefomgeving. Het PBL verkende wat het betekent om mobiliteitsbeleid vanuit een bredewelvaartsperspectief te benaderen, waarbij niet alleen reistijdwinst maar ook gezondheid, sociale inclusie en milieu worden meegewogen.", "citations": [{"source_id": {"instituut": "PBL", "titel": "Brede welvaart en mobiliteit", "jaar": "2021", "auteur": "PBL", "url": "https://www.pbl.nl/publicaties/brede-welvaart-en-mobiliteit", "lokaal_pad": ""}, "page": 3}, {"source_id": {"instituut": "PBL", "titel": "Brede welvaart en mobiliteit", "jaar": "2021", "auteur": "PBL", "url": "https://www.pbl.nl/publicaties/brede-welvaart-en-mobiliteit", "lokaal_pad": ""}, "page": 7}]}, {"type": "h2", "text": "Toegang tot voorzieningen", "citations": []}, {"type": "p", "text": "Het KiM onderzocht hoe brede welvaart een nieuw kader biedt voor mobiliteitsmonitoring. Bereikbaarheid van zorg, onderwijs, winkels en cultuur is een indicator in de Monitor Brede Welvaart van het CBS. In krimpgebieden staan deze voorzieningen onder druk, wat direct de kwaliteit van leven raakt. Het SCP beschouwt toegang tot voorzieningen als een kernaspect van sociale kwaliteit.", "citations": [{"source_id": {"instituut": "KiM", "titel": "Uitwerking van brede welvaart voor mobiliteitsmonitoring", "jaar": "2021", "auteur": "KiM", "url": "https://www.kimnet.nl/documenten/2021/12/01/uitwerking-van-brede-welvaart-voor-de-monitoring-en-evaluatie-van-mobiliteitsbeleid", "lokaal_pad": ""}, "page": 3}, {"source_id": {"instituut": "CBS", "titel": "Monitor Brede Welvaart & SDG's", "jaar": "2024", "auteur": "CBS", "url": "https://www.cbs.nl/nl-nl/dossier/dossier-brede-welvaart-en-de-sustainable-development-goals", "lokaal_pad": ""}, "page": 3}, {"source_id": {"instituut": "SCP", "titel": "Brede welvaart en kwaliteit van de samenleving", "jaar": "2024", "auteur": "SCP", "url": "https://www.scp.nl/documenten/2024/02/28/brede-welvaart-en-kwaliteit-van-de-samenleving", "lokaal_pad": ""}, "page": 6}]}], "see_also": ["regionale-brede-welvaart", "gezondheid-natuur-milieu"], "tags": ["Wonen", "Mobiliteit", "PBL", "KiM", "RLI", "Bereikbaarheid", "Voorzieningen"]}, {"id": "circulair-klimaat", "title": "Circulaire economie, klimaat en duurzame ontwikkeling", "thema": "kwaliteit-van-leven", "cluster": "8. Circulaire economie, klimaat en SDG's", "meta": "Bronnen: CPB (5 documenten uit het beleidscorpus)", "sections": [{"type": "h2", "text": "Circulaire economie", "citations": []}, {"type": "p", "text": "In 2018 verscheen de eerste Verkenning Brede Welvaart, waarin PBL, CPB en SCP de rol van de transitie naar een circulaire economie onderzochten. De verkenning liet zien dat een circulaire economie niet alleen over grondstoffengebruik gaat, maar over fundamentele keuzes in consumptiepatronen, productiemethoden en de verdeling van welvaart.", "citations": [{"source_id": {"instituut": "PBL", "titel": "Verkenning Brede Welvaart - circulaire economie", "jaar": "2018", "auteur": "PBL, CPB, SCP", "url": "https://www.pbl.nl/publicaties/verkenning-brede-welvaart-circulaire-economie-gedrag-en-beleid", "lokaal_pad": ""}, "page": 3}]}, {"type": "p", "text": "Nederland is sterk afhankelijk van import van grondstoffen. De RLI adviseert dat de transitie naar circulair grondstoffengebruik noodzakelijk is voor toekomstige welvaart. Het CPB voegt hieraan toe dat grondstoffenefficiëntie kan bijdragen aan zowel economische als ecologische doelstellingen.", "citations": [{"source_id": {"instituut": "RLI", "titel": "Circulaire economie: van wens naar uitvoering", "jaar": "2015", "auteur": "RLI", "url": "https://www.rli.nl/publicaties/2015/advies/circulaire-economie-van-wens-naar-uitvoering", "lokaal_pad": ""}, "page": 4}, {"source_id": {"instituut": "CPB", "titel": "Richting van de energietransitie", "jaar": "2015", "auteur": "CPB", "url": "https://www.cpb.nl/publicatie/richting-van-de-energietransitie-nog-niet-bekend", "lokaal_pad": ""}, "page": 4}]}, {"type": "h2", "text": "Klimaat en energie", "citations": []}, {"type": "p", "text": "Klimaatbeleid heeft effecten op alle dimensies van [[brede-welvaart-concept:brede welvaart]]: economie, gezondheid, sociale cohesie en leefomgeving. De energietransitie vraagt om integrale afwegingen, aldus de RLI. Het CPB benadrukt dat de kosten van klimaatbeleid moeten worden afgewogen tegen de baten van het voorkomen van toekomstige schade.", "citations": [{"source_id": {"instituut": "PBL", "titel": "Verkenning Brede Welvaart - circulaire economie", "jaar": "2018", "auteur": "PBL, CPB, SCP", "url": "https://www.pbl.nl/publicaties/verkenning-brede-welvaart-circulaire-economie-gedrag-en-beleid", "lokaal_pad": ""}, "page": 6}, {"source_id": {"instituut": "RLI", "titel": "Energietransitie en leefomgeving", "jaar": "2017", "auteur": "RLI", "url": "https://www.rli.nl/publicaties/2017/publicatie/kennisnotitie-energietransitie-en-leefomgeving", "lokaal_pad": ""}, "page": 4}, {"source_id": {"instituut": "CPB", "titel": "Richting van de energietransitie", "jaar": "2015", "auteur": "CPB", "url": "https://www.cpb.nl/publicatie/richting-van-de-energietransitie-nog-niet-bekend", "lokaal_pad": ""}, "page": 5}]}, {"type": "h2", "text": "Duurzame ontwikkelingsdoelen (SDG's)", "citations": []}, {"type": "p", "text": "Brede welvaart en de Sustainable Development Goals delen een integrale benadering van welzijn, maar verschillen in schaal en reikwijdte. Waar de SDG's een mondiaal raamwerk met 17 doelen en 169 targets bieden, is brede welvaart flexibeler per regio in te vullen. Het CBS combineert beide in zijn jaarlijkse monitor.", "citations": [{"source_id": {"instituut": "PBL", "titel": "Brede welvaart en de SDG's", "jaar": "2023", "auteur": "PBL", "url": "https://www.pbl.nl/publicaties/brede-welvaart-en-de-sdgs", "lokaal_pad": ""}, "page": 3}, {"source_id": {"instituut": "CBS", "titel": "Monitor Brede Welvaart & SDG's", "jaar": "2024", "auteur": "CBS", "url": "https://www.cbs.nl/nl-nl/dossier/dossier-brede-welvaart-en-de-sustainable-development-goals", "lokaal_pad": ""}, "page": 4}]}], "see_also": ["sociale-ongelijkheid", "gezondheid-natuur-milieu"], "tags": ["Circulair", "Klimaat", "Energie", "SDG's", "PBL", "RLI", "CPB"]}, {"id": "begroting-mkba", "title": "Begrotingssystematiek, MKBA en monitoring", "thema": "kwaliteit-van-leven", "cluster": "9. Begroting, MKBA en monitoring", "meta": "Bronnen: CPB (5 documenten uit het beleidscorpus)", "sections": [{"type": "h2", "text": "Verankering in de begrotingssystematiek", "citations": []}, {"type": "p", "text": "In 2021 sprak de Tweede Kamer de wens uit om brede welvaart beter te integreren in de begrotings- en verantwoordingssystematiek. De drie planbureaus hebben hiervoor gezamenlijk een plan van aanpak opgesteld. Centraal staat de ontwikkeling van een Kernset Indicatoren Brede Welvaart waarmee beleidseffecten systematisch worden gemeten, vergelijkbaar met hoe de Rijksbegroting financiële effecten in kaart brengt.", "citations": [{"source_id": {"instituut": "SCP", "titel": "Verankering van brede welvaart in begrotingssystematiek", "jaar": "2022", "auteur": "SCP, PBL, CPB", "url": "https://www.scp.nl/documenten/2022/06/30/verankering-van-brede-welvaart-in-de-begrotingssystematiek", "lokaal_pad": ""}, "page": 3}]}, {"type": "p", "text": "De planbureaus constateren dat er vooruitgang is geboekt, maar dat de koppeling tussen beleidsuitgaven en bredewelvaartseffecten complex blijft. Het PBL stelt dat een integrale afweging vraagt om politieke keuzes die de wetenschap niet kan maken.", "citations": [{"source_id": {"instituut": "CPB", "titel": "Verkenning Brede Welvaart 2018", "jaar": "2018", "auteur": "CPB, PBL, SCP", "url": "https://www.cpb.nl/publicatie/naar-een-verkenning-brede-welvaart", "lokaal_pad": ""}, "page": 10}, {"source_id": {"instituut": "PBL", "titel": "Reflectie brede welvaart: Prinsjesdag 2024", "jaar": "2024", "auteur": "PBL", "url": "https://www.pbl.nl/publicaties/reflectie-brede-welvaart-prinsjesdag-2024", "lokaal_pad": ""}, "page": 3}]}, {"type": "h2", "text": "MKBA en brede welvaart", "citations": []}, {"type": "p", "text": "In 2022 onderzochten CPB en PBL hoe de maatschappelijke kosten-batenanalyse (MKBA) kan worden verrijkt met een bredewelvaartsperspectief. Waar een traditionele MKBA effecten zoveel mogelijk monetariseert, vraagt brede welvaart om een bredere blik die ook niet-monetariseerbare effecten meeweegt, verdelingseffecten expliciet maakt en effecten op toekomstige generaties meeneemt.", "citations": [{"source_id": {"instituut": "CPB", "titel": "Maatschappelijke kosten-batenanalyse en brede welvaart", "jaar": "2022", "auteur": "CPB & PBL", "url": "https://www.cpb.nl/maatschappelijke-kosten-batenanalyse-en-brede-welvaart-een-aanvulling-op-de-algemene-mkba-leidraad", "lokaal_pad": ""}, "page": 3}, {"source_id": {"instituut": "CPB", "titel": "MKBA en brede welvaart", "jaar": "2022", "auteur": "CPB & PBL", "url": "https://www.cpb.nl/publicatie/wlo-klimaatscenarios-en-de-waardering-van-co2-uitstoot-mkbas", "lokaal_pad": ""}, "page": 3}]}, {"type": "h2", "text": "Monitoring", "citations": []}, {"type": "p", "text": "De jaarlijkse Monitor Brede Welvaart van het CBS is het belangrijkste instrument voor structurele monitoring. Het PBL ontwikkelde daarnaast methoden voor monitoring op gemeentelijk en provinciaal niveau. Het SCP benadrukt dat monitoring alleen niet genoeg is: er is ook kwalitatieve evaluatie nodig die recht doet aan de normatieve dimensie van [[brede-welvaart-concept:brede welvaart]].", "citations": [{"source_id": {"instituut": "CBS", "titel": "Monitor Brede Welvaart & SDG's", "jaar": "2024", "auteur": "CBS", "url": "https://www.cbs.nl/nl-nl/dossier/dossier-brede-welvaart-en-de-sustainable-development-goals", "lokaal_pad": ""}, "page": 3}, {"source_id": {"instituut": "PBL", "titel": "Brede welvaart in Nederlandse gemeenten", "jaar": "2022", "auteur": "PBL", "url": "https://www.pbl.nl/publicaties/brede-welvaart-in-nederlandse-gemeenten-het-belang-van-regionale-samenhang", "lokaal_pad": ""}, "page": 6}, {"source_id": {"instituut": "SCP", "titel": "Verankering van brede welvaart in begrotingssystematiek", "jaar": "2022", "auteur": "SCP, PBL, CPB", "url": "https://www.scp.nl/documenten/2022/06/30/verankering-van-brede-welvaart-in-de-begrotingssystematiek", "lokaal_pad": ""}, "page": 5}]}], "see_also": ["brede-welvaart-concept", "sociaaleconomisch"], "tags": ["Begroting", "MKBA", "CPB", "PBL", "SCP", "CBS", "Monitoring"]}, {"id": "bestuur-rechtvaardigheid", "title": "Bestuur, politieke keuzes en rechtvaardigheid", "thema": "kwaliteit-van-leven", "cluster": "10. Bestuur en rechtvaardigheid", "meta": "Bronnen: CPB (5 documenten uit het beleidscorpus)", "sections": [{"type": "h2", "text": "Brede welvaart is politiek", "citations": []}, {"type": "p", "text": "Wat van waarde is, wie profiteert en wie betaalt — dat zijn politieke vragen, geen wetenschappelijke. Al in 2020 benadrukte het PBL dat aan elk beleid voor brede welvaart normatieve opvattingen ten grondslag liggen over wat een rechtvaardige verdeling van welvaart is.", "citations": [{"source_id": {"instituut": "PBL", "titel": "Bevorderen van brede welvaart in de regio", "jaar": "2020", "auteur": "PBL", "url": "https://www.pbl.nl/publicaties/bevorderen-van-brede-welvaart-in-de-regio-keuzes-voor-beleid", "lokaal_pad": ""}, "page": 3}, {"source_id": {"instituut": "PBL", "titel": "Brede welvaart in elke regio", "jaar": "2024", "auteur": "Weterings e.a.", "url": "https://www.pbl.nl/publicaties/brede-welvaart-in-elke-regio", "lokaal_pad": ""}, "page": 4}]}, {"type": "h2", "text": "Drie opvattingen over rechtvaardige verdeling", "citations": []}, {"type": "p", "text": "Het PBL onderscheidt drie fundamentele opvattingen: maximaliseren (de meeste welvaart voor Nederland als geheel), verminderen van verschillen (regionale ongelijkheid verkleinen) en voldoende voor iedereen (een minimumnorm per regio). De WRR voegt hieraan toe dat brede welvaart dwingt tot expliciete afwegingen van afruilen tussen economische, sociale en ecologische doelen.", "citations": [{"source_id": {"instituut": "PBL", "titel": "Brede welvaart in elke regio", "jaar": "2024", "auteur": "Weterings e.a.", "url": "https://www.pbl.nl/publicaties/brede-welvaart-in-elke-regio", "lokaal_pad": ""}, "page": 11}, {"source_id": {"instituut": "WRR", "titel": "Theorieën van de onderneming - brede welvaart", "jaar": "2022", "auteur": "WRR", "url": "https://www.wrr.nl/documenten/2022/03/15/theorieen-van-de-onderneming", "lokaal_pad": ""}, "page": 6}]}, {"type": "h2", "text": "Interbestuurlijke verhoudingen", "citations": []}, {"type": "p", "text": "Brede welvaart raakt aan taken van alle overheidslagen: Rijk, provincies, gemeenten en waterschappen. De ROB adviseert over de bestuurlijke consequenties van een bredewelvaartsbenadering. Het provinciaal niveau is bij uitstek geschikt om regionale opgaven te regisseren, Rijk en gemeenten te verbinden en maatschappelijke partners te betrekken.", "citations": [{"source_id": {"instituut": "ROB", "titel": "Brede welvaart, grote opgaven", "jaar": "2022", "auteur": "ROB", "url": "https://www.raadopenbaarbestuur.nl/documenten/2022/04/12/brede-welvaart-grote-opgaven", "lokaal_pad": ""}, "page": 4}, {"source_id": {"instituut": "ROB", "titel": "Lef en evenwicht - financiële verhoudingen", "jaar": "2024", "auteur": "ROB", "url": "https://www.raadopenbaarbestuur.nl/documenten/2024/02/29/briefadvies-raamwerk-toekomstbestendige-financiele-verhoudingen", "lokaal_pad": ""}, "page": 3}]}, {"type": "h2", "text": "Sociale rechtvaardigheid", "citations": []}, {"type": "p", "text": "Het SCP benadrukt dat sociale rechtvaardigheid niet alleen over inkomen gaat maar ook over toegang tot voorzieningen en kansen. Een rechtvaardige verdeling van [[brede-welvaart-concept:brede welvaart]] vraagt om beleid dat oog heeft voor zowel economische, sociale als ecologische dimensies, nu en voor toekomstige generaties.", "citations": [{"source_id": {"instituut": "SCP", "titel": "Verschil in Nederland 2014-2020", "jaar": "2014", "auteur": "SCP", "url": "https://www.scp.nl/documenten/2014/12/12/verschil-in-nederland-2014", "lokaal_pad": ""}, "page": 8}, {"source_id": {"instituut": "SCP", "titel": "Brede welvaart en kwaliteit van de samenleving", "jaar": "2024", "auteur": "SCP", "url": "https://www.scp.nl/documenten/2024/02/28/brede-welvaart-en-kwaliteit-van-de-samenleving", "lokaal_pad": ""}, "page": 7}]}], "see_also": ["sociale-ongelijkheid", "regionale-brede-welvaart", "begroting-mkba"], "tags": ["Bestuur", "Rechtvaardigheid", "PBL", "ROB", "WRR", "SCP", "Politiek"]}, {"id": "onderwijs-cultuur", "title": "Onderwijs, cultuur, sport en vrije tijd", "thema": "kwaliteit-van-leven", "cluster": "11. Onderwijs, cultuur, sport en vrije tijd", "meta": "Bronnen: CPB (5 documenten uit het beleidscorpus)", "sections": [{"type": "h2", "text": "Onderwijs en brede welvaart", "citations": []}, {"type": "p", "text": "Onderwijs draagt op meerdere manieren bij aan brede welvaart: via kennis en vaardigheden, sociale mobiliteit, burgerschap en persoonlijke ontwikkeling. Het SCP constateert dat onderwijs een sleutelrol speelt in het doorbreken van intergenerationele armoede en het verkleinen van kansenongelijkheid.", "citations": [{"source_id": {"instituut": "SCP", "titel": "Verschil in Nederland 2014-2020", "jaar": "2014", "auteur": "SCP", "url": "https://www.scp.nl/documenten/2014/12/12/verschil-in-nederland-2014", "lokaal_pad": ""}, "page": 6}, {"source_id": {"instituut": "SCP", "titel": "Brede welvaart en kwaliteit van de samenleving", "jaar": "2024", "auteur": "SCP", "url": "https://www.scp.nl/documenten/2024/02/28/brede-welvaart-en-kwaliteit-van-de-samenleving", "lokaal_pad": ""}, "page": 7}]}, {"type": "h2", "text": "Cultuurparticipatie", "citations": []}, {"type": "p", "text": "Cultuur draagt bij aan zingeving, sociale verbinding en identiteit. Deelname aan culturele activiteiten is echter ongelijk verdeeld over inkomens- en opleidingsgroepen, zo blijkt uit de Monitor Brede Welvaart. Het SCP beschouwt cultuurparticipatie als een indicator voor de kwaliteit van de samenleving.", "citations": [{"source_id": {"instituut": "SCP", "titel": "Brede welvaart en kwaliteit van de samenleving", "jaar": "2024", "auteur": "SCP", "url": "https://www.scp.nl/documenten/2024/02/28/brede-welvaart-en-kwaliteit-van-de-samenleving", "lokaal_pad": ""}, "page": 7}, {"source_id": {"instituut": "CBS", "titel": "Monitor Brede Welvaart & SDG's", "jaar": "2024", "auteur": "CBS", "url": "https://www.cbs.nl/nl-nl/dossier/dossier-brede-welvaart-en-de-sustainable-development-goals", "lokaal_pad": ""}, "page": 5}]}, {"type": "h2", "text": "Sport en vrije tijd", "citations": []}, {"type": "p", "text": "Sport en bewegen dragen bij aan fysieke en mentale gezondheid. Sportverenigingen zijn daarnaast een belangrijke bron van sociale cohesie. Hoe mensen hun tijd besteden — werk, zorg, vrije tijd, slaap — is een belangrijke indicator voor de ervaren kwaliteit van leven, zoals het SCP in zijn onderzoek benadrukt.", "citations": [{"source_id": {"instituut": "RIVM", "titel": "Monitor Gezonde Leefomgeving", "jaar": "2020", "auteur": "RIVM", "url": "https://www.rivm.nl/publicaties/regios-in-beweging-naar-toekomstbestendig-gezondheidssysteem", "lokaal_pad": ""}, "page": 6}, {"source_id": {"instituut": "SCP", "titel": "Brede welvaart en kwaliteit van de samenleving", "jaar": "2024", "auteur": "SCP", "url": "https://www.scp.nl/documenten/2024/02/28/brede-welvaart-en-kwaliteit-van-de-samenleving", "lokaal_pad": ""}, "page": 6}]}], "see_also": ["gezondheid-natuur-milieu", "bestaanszekerheid-sociaal"], "tags": ["Onderwijs", "Cultuur", "Sport", "Vrije tijd", "SCP", "CBS", "RIVM"]}, {"id": "internationaal-migratie", "title": "Internationale vergelijking en migratie", "thema": "kwaliteit-van-leven", "cluster": "12. Internationaal en migratie", "meta": "Bronnen: CPB (5 documenten uit het beleidscorpus)", "sections": [{"type": "h2", "text": "Nederland in internationaal perspectief", "citations": []}, {"type": "p", "text": "De Monitor Brede Welvaart van het CBS vergelijkt Nederland met andere EU-landen. Nederland scoort hoog op inkomen, werk, onderwijs en subjectief welzijn, maar heeft uitdagingen op het gebied van milieu, wonen en vermogensongelijkheid. De OESO Better Life Index en de [[circulair-klimaat:SDG's]] bieden internationale referentiekaders voor nationaal beleid.", "citations": [{"source_id": {"instituut": "CBS", "titel": "Monitor Brede Welvaart & SDG's", "jaar": "2024", "auteur": "CBS", "url": "https://www.cbs.nl/nl-nl/dossier/dossier-brede-welvaart-en-de-sustainable-development-goals", "lokaal_pad": ""}, "page": 4}]}, {"type": "h2", "text": "Migratie en brede welvaart", "citations": []}, {"type": "p", "text": "Migratie heeft effecten op brede welvaart via de arbeidsmarkt, publieke voorzieningen en sociale cohesie. Het CPB analyseerde de economische effecten van arbeidsmigratie, die bijdraagt aan economische groei maar ook verdelingseffecten heeft die om beleid vragen. De WRR onderzocht de integratie van migranten, een langetermijnproces dat vraagt om investeringen in taal, werk en onderwijs.", "citations": [{"source_id": {"instituut": "CPB", "titel": "Aspecten van brede welvaart in CPB-studies", "jaar": "2016", "auteur": "CPB", "url": "https://www.cpb.nl/publicatie/aspecten-van-brede-welvaart-in-cpb-studies", "lokaal_pad": ""}, "page": 8}, {"source_id": {"instituut": "WRR", "titel": "Migratiediversiteit beter in beeld", "jaar": "2015", "auteur": "WRR", "url": "https://www.wrr.nl/documenten/2015/10/28/migratiediversiteit-beter-in-beeld", "lokaal_pad": ""}, "page": 3}]}, {"type": "h2", "text": "Sociaaleconomische aspecten van migratie", "citations": []}, {"type": "p", "text": "Het SCP volgt de effecten van migratie op de sociale kwaliteit van de samenleving. De SER adviseert over arbeidsmigratie en de effecten op de arbeidsmarkt en sociale voorzieningen. De WRR pleit voor een beleid dat migratie niet alleen als economisch fenomeen benadert maar ook oog heeft voor maatschappelijke integratie en sociale cohesie.", "citations": [{"source_id": {"instituut": "SER", "titel": "Verhogen maatschappelijke welvaart via arbeidsinzet", "jaar": "2015", "auteur": "SER", "url": "https://www.ser.nl/-/media/ser/downloads/overige-publicaties/2015/verhogen-maatschappelijke-welvaart.pdf", "lokaal_pad": ""}, "page": 4}, {"source_id": {"instituut": "SCP", "titel": "Burgerperspectieven Bericht 1 2026 - Thema Brede Welvaart", "jaar": "2026", "auteur": "SCP", "url": "https://www.scp.nl/documenten/2026/02/05/burgerperspectieven-bericht-1-2026-thema-brede-welvaart", "lokaal_pad": ""}, "page": 6}]}], "see_also": ["sociale-ongelijkheid", "bestaanszekerheid-sociaal"], "tags": ["Internationaal", "Migratie", "CBS", "SCP", "WRR", "CPB", "SER"]}, {"id": "toekomstverkenningen", "title": "Toekomstverkenningen en scenario's", "thema": "kwaliteit-van-leven", "cluster": "13. Toekomstverkenningen", "meta": "Bronnen: CPB (5 documenten uit het beleidscorpus)", "sections": [{"type": "h2", "text": "Waarom toekomstverkenningen?", "citations": []}, {"type": "p", "text": "Brede welvaart is bij uitstek een langetermijnconcept dat vraagt om een blik vooruit. PBL, CPB en WRR maken regelmatig toekomstverkenningen die scenariodenken combineren met bredewelvaartsanalyse. Deze verkenningen helpen beleid robuust te maken voor onzekere toekomstige ontwikkelingen.", "citations": [{"source_id": {"instituut": "PBL", "titel": "Verkenning Brede Welvaart - circulaire economie", "jaar": "2018", "auteur": "PBL, CPB, SCP", "url": "https://www.pbl.nl/publicaties/verkenning-brede-welvaart-circulaire-economie-gedrag-en-beleid", "lokaal_pad": ""}, "page": 4}, {"source_id": {"instituut": "WRR", "titel": "Navigeren en anticiperen in onzekere tijden", "jaar": "2021", "auteur": "WRR & KNAW", "url": "https://www.wrr.nl/documenten/2021/09/02/navigeren-en-anticiperen-in-onzekere-tijden", "lokaal_pad": ""}, "page": 4}]}, {"type": "h2", "text": "PBL- en CPB-verkenningen", "citations": []}, {"type": "p", "text": "De Welvaart en Leefomgeving-verkenningen van het PBL schetsen scenario's voor demografie, economie, klimaat en energie. Het CPB voegt daar macro-economische scenario's aan toe. De kracht van deze verkenningen is dat ze beleidsmakers dwingen na te denken over afruilen tussen verschillende doelen en over de effecten van keuzes op de lange termijn.", "citations": [{"source_id": {"instituut": "PBL", "titel": "Verkenning Brede Welvaart - circulaire economie", "jaar": "2018", "auteur": "PBL, CPB, SCP", "url": "https://www.pbl.nl/publicaties/verkenning-brede-welvaart-circulaire-economie-gedrag-en-beleid", "lokaal_pad": ""}, "page": 6}, {"source_id": {"instituut": "CPB", "titel": "Verkenning Brede Welvaart 2018", "jaar": "2018", "auteur": "CPB, PBL, SCP", "url": "https://www.cpb.nl/publicatie/naar-een-verkenning-brede-welvaart", "lokaal_pad": ""}, "page": 8}]}, {"type": "h2", "text": "WRR: navigeren in onzekere tijden", "citations": []}, {"type": "p", "text": "De WRR ontwikkelde methoden voor het omgaan met onzekerheid in beleid. In 2021 adviseerden WRR en KNAW gezamenlijk dat beleid niet alleen moet reageren op huidige problemen maar ook moet anticiperen op toekomstige ontwikkelingen. Dit vereist een lerende, adaptieve overheid die kan bijsturen als omstandigheden veranderen.", "citations": [{"source_id": {"instituut": "WRR", "titel": "Navigeren en anticiperen in onzekere tijden", "jaar": "2021", "auteur": "WRR & KNAW", "url": "https://www.wrr.nl/documenten/2021/09/02/navigeren-en-anticiperen-in-onzekere-tijden", "lokaal_pad": ""}, "page": 6}]}, {"type": "h2", "text": "Toepassing in provinciaal beleid", "citations": []}, {"type": "p", "text": "De strategische kennisagenda van de provincie Utrecht (2026-2027) gebruikt scenario's om voor te sorteren op verschillende toekomsten. De combinatie van demografische ontwikkelingen, klimaatverandering, technologische innovatie en Europese beleidsontwikkelingen maakt dat provincies niet kunnen volstaan met een eenmalige beleidscyclus, maar continu moeten blijven leren en aanpassen. Dit raakt aan het bredere thema van [[bestuur-rechtvaardigheid:bestuurlijke veerkracht]].", "citations": [{"source_id": {"instituut": "PBL", "titel": "Nieuwe perspectieven voor groeikernen", "jaar": "2015", "auteur": "PBL", "url": "https://www.pbl.nl/publicaties/een-nieuw-perspectief-voor-oude-groeikernen", "lokaal_pad": ""}, "page": 4}, {"source_id": {"instituut": "SCP", "titel": "Brede welvaart en kwaliteit van de samenleving", "jaar": "2024", "auteur": "SCP", "url": "https://www.scp.nl/documenten/2024/02/28/brede-welvaart-en-kwaliteit-van-de-samenleving", "lokaal_pad": ""}, "page": 7}]}], "see_also": ["circulair-klimaat", "sociale-ongelijkheid", "regionale-brede-welvaart"], "tags": ["Toekomst", "Scenario's", "WRR", "PBL", "CPB", "Verkenningen", "Lange termijn"]}, {"id": "sociale-cohesie", "title": "Sociale cohesie, vertrouwen en maatschappelijke betrokkenheid", "thema": "verbonden-samenleving", "cluster": "1. Sociale cohesie", "meta": "Bronnen: CPB (5 documenten uit het beleidscorpus)", "sections": [{"type": "h2", "text": "Wat is sociale cohesie?", "citations": []}, {"type": "p", "text": "Sociale cohesie verwijst naar de mate van verbondenheid tussen mensen in een samenleving: onderling vertrouwen, gedeelde normen en waarden, en de bereidheid om samen te werken aan gemeenschappelijke doelen. Het SCP beschouwt sociale cohesie als een van de pijlers van de kwaliteit van de samenleving, naast maatschappelijke betrokkenheid, vertrouwen in instituties en ervaren kwaliteit van leven.", "citations": [{"source_id": {"instituut": "SCP", "titel": "Brede welvaart en kwaliteit van de samenleving", "jaar": "2024", "auteur": "SCP", "url": "https://www.scp.nl/documenten/2024/02/28/brede-welvaart-en-kwaliteit-van-de-samenleving", "lokaal_pad": ""}, "page": 3}]}, {"type": "p", "text": "In 2017 bracht het SCP in De sociale staat van Nederland in kaart dat Nederland internationaal gezien hoog scoort op vertrouwen en sociale cohesie, maar dat er duidelijke verschillen bestaan tussen bevolkingsgroepen. Jongeren, lager opgeleiden en stedelingen vertonen andere sociale netwerken en vertrouwenspatronen dan ouderen, hoger opgeleiden en inwoners van landelijke gebieden.", "citations": [{"source_id": {"instituut": "SCP", "titel": "De sociale staat van Nederland 2017", "jaar": "2017", "auteur": "SCP", "url": "https://repository.scp.nl/?atabase=9eb0bac7-6d6f-490e-b252-789aef5aeca7", "lokaal_pad": ""}, "page": 5}]}, {"type": "h2", "text": "Vertrouwen in instituties", "citations": []}, {"type": "p", "text": "Vertrouwen in instituties — overheid, politiek, rechtspraak, media, wetenschap — is een belangrijke indicator voor de kwaliteit van een samenleving. De ROB wees er in 2006 op dat bouwen aan vertrouwen in het openbaar bestuur een langdurig proces is dat vraagt om transparantie, integriteit en responsiviteit. Het Rathenau Instituut volgt sinds 2012 het vertrouwen in de wetenschap, dat ondanks politieke en maatschappelijke spanningen relatief stabiel blijft.", "citations": [{"source_id": {"instituut": "ROB", "titel": "Bouwen aan vertrouwen in het openbaar bestuur", "jaar": "2006", "auteur": "ROB", "url": "https://www.raadopenbaarbestuur.nl/documenten/2006/12/18/bouwen-aan-vertrouwen-in-het-openbaar-bestuur", "lokaal_pad": ""}, "page": 4}, {"source_id": {"instituut": "Rathenau", "titel": "Vertrouwen in de wetenschap 2018", "jaar": "2018", "auteur": "Rathenau", "url": "https://www.rathenau.nl/nl/werking-van-het-wetenschapssysteem/vertrouwen-de-wetenschap-2018", "lokaal_pad": ""}, "page": 3}]}, {"type": "h2", "text": "Maatschappelijke betrokkenheid", "citations": []}, {"type": "p", "text": "Vrijwilligerswerk, lidmaatschap van verenigingen en burgerinitiatieven zijn vormen van maatschappelijke betrokkenheid die bijdragen aan sociale cohesie. Het SCP constateert dat de traditionele verenigingsstructuur onder druk staat door individualisering, maar dat nieuwe vormen van betrokkenheid opkomen, zoals online communities, buurtinitiatieven en eenmalige vrijwilligersacties.", "citations": [{"source_id": {"instituut": "SCP", "titel": "De sociale staat van Nederland 2017", "jaar": "2017", "auteur": "SCP", "url": "https://repository.scp.nl/?atabase=9eb0bac7-6d6f-490e-b252-789aef5aeca7", "lokaal_pad": ""}, "page": 7}, {"source_id": {"instituut": "SCP", "titel": "Brede welvaart en kwaliteit van de samenleving", "jaar": "2024", "auteur": "SCP", "url": "https://www.scp.nl/documenten/2024/02/28/brede-welvaart-en-kwaliteit-van-de-samenleving", "lokaal_pad": ""}, "page": 5}]}, {"type": "h2", "text": "Eenzaamheid als tegenkracht", "citations": []}, {"type": "p", "text": "Het SCP besteedt in zijn onderzoek aandacht aan eenzaamheid, een groeiend maatschappelijk probleem dat de sociale cohesie ondermijnt. Eenzaamheid treft niet alleen ouderen, maar ook jongeren en migranten. Het doorbreken van eenzaamheid vraagt om een integrale aanpak van zorg, welzijn, wonen en vervoer.", "citations": [{"source_id": {"instituut": "CPB", "titel": "Honderd jaar kosten-batenanalyse waterveiligheid in Nederland", "jaar": "2017", "auteur": "", "url": "https://www.cpb.nl/publicatie/honderd-jaar-kostenbatenanalyse-waterveiligheid-in-nederland"}}]}], "see_also": ["polarisatie-onbehagen", "migratie-integratie", "burgerparticipatie"], "tags": []}, {"id": "polarisatie-onbehagen", "title": "Polarisatie en maatschappelijk onbehagen", "thema": "verbonden-samenleving", "cluster": "2. Polarisatie", "meta": "Bronnen: CPB, PBL, SCP (5 documenten uit het beleidscorpus)", "sections": [{"type": "h2", "text": "Polarisatie in Nederland", "citations": []}, {"type": "p", "text": "Polarisatie verwijst naar het proces waarbij de tegenstellingen tussen bevolkingsgroepen in de samenleving scherper worden. Het SCP constateert in zijn Burgerperspectieven-berichten dat de ervaren kloof tussen bevolkingsgroepen groter is dan de feitelijke verschillen in inkomen, opleiding en maatschappelijke positie.", "citations": [{"source_id": {"instituut": "SCP", "titel": "Burgerperspectieven Bericht 3 2025 - Maatschappelijk onbehagen", "jaar": "2025", "auteur": "SCP", "url": "https://www.scp.nl/documenten/2025/10/20/burgerperspectieven-2025-bericht-3", "lokaal_pad": ""}, "page": 4}]}, {"type": "h2", "text": "Maatschappelijk onbehagen", "citations": []}, {"type": "p", "text": "Het SCP signaleert een breed gedragen gevoel van maatschappelijk onbehagen: mensen maken zich zorgen over de toekomst, voelen zich niet gehoord door de politiek en ervaren een verlies van grip op hun eigen leven. Dit onbehagen is niet beperkt tot één bevolkingsgroep, maar is het sterkst onder mensen met een lagere sociaaleconomische status en in regio's die economisch achterblijven.", "citations": [{"source_id": {"instituut": "SCP", "titel": "Burgerperspectieven Bericht 3 2025 - Maatschappelijk onbehagen", "jaar": "2025", "auteur": "SCP", "url": "https://www.scp.nl/documenten/2025/10/20/burgerperspectieven-2025-bericht-3", "lokaal_pad": ""}, "page": 5}, {"source_id": {"instituut": "SCP", "titel": "De sociale staat van Nederland 2017", "jaar": "2017", "auteur": "SCP", "url": "https://repository.scp.nl/?atabase=9eb0bac7-6d6f-490e-b252-789aef5aeca7", "lokaal_pad": ""}, "page": 6}]}, {"type": "h2", "text": "Arbeidsmarktpolinsarisatie", "citations": []}, {"type": "p", "text": "Het CPB beschrijft hoe de arbeidsmarkt polariseert: middeninkomensbanen verdwijnen, terwijl zowel laag- als hoogopgeleid werk groeit. Dit proces draagt bij aan het gevoel van achterblijven bij groepen die in het middensegment van de arbeidsmarkt zitten. De WRR onderzocht hoe deze ongelijkheid doorwerkt in het vertrouwen in instituties.", "citations": [{"source_id": {"instituut": "CPB", "titel": "Baanpolarisatie in Nederland", "jaar": "2015", "auteur": "CPB", "url": "https://www.cpb.nl/publicatie/baanpolarisatie-in-nederland", "lokaal_pad": ""}, "page": 3}, {"source_id": {"instituut": "WRR", "titel": "Kwetsbaarheid en veerkracht", "jaar": "2020", "auteur": "WRR", "url": "https://www.wrr.nl/documenten/2020/06/16/kwetsbaarheid-en-veerkracht", "lokaal_pad": ""}, "page": 5}]}, {"type": "h2", "text": "Beleidsaanpak", "citations": []}, {"type": "p", "text": "Het tegengaan van polarisatie vraagt om een combinatie van sociaaleconomisch beleid (banen, inkomen, wonen) en sociale interventies (ontmoeting, dialoog, burgerschap). De provincie Utrecht kan hier een rol spelen via regionaal arbeidsmarktbeleid, woningbouw en het stimuleren van ontmoetingsplekken in wijken en dorpen.", "citations": [{"source_id": {"instituut": "CPB", "titel": "Arbeidsmarktpolarisatie op regionaal niveau", "jaar": "2017", "auteur": "", "url": "https://www.cpb.nl/publicatie/arbeidsmarktpolarisatie-op-regionaal-niveau"}}]}], "see_also": ["sociale-cohesie", "migratie-integratie", "burgerparticipatie"], "tags": []}, {"id": "migratie-integratie", "title": "Migratie, integratie en diversiteit", "thema": "verbonden-samenleving", "cluster": "3. Migratie en integratie", "meta": "Bronnen: CPB (5 documenten uit het beleidscorpus)", "sections": [{"type": "h2", "text": "Migratie in Nederlands perspectief", "citations": []}, {"type": "p", "text": "Nederland kent een lange geschiedenis van migratie. De WRR benadrukt in diverse publicaties dat migratie een structureel fenomeen is, geen tijdelijk. Een goed migratiebeleid erkent dat migratie zowel kansen biedt (arbeidsmarkt, innovatie, culturele verrijking) als uitdagingen stelt (woningmarkt, voorzieningen, sociale cohesie).", "citations": [{"source_id": {"instituut": "WRR", "titel": "Geen tijd verliezen: van opvang naar integratie van asielmigranten", "jaar": "2015", "auteur": "WRR", "url": "https://www.wrr.nl/documenten/2015/12/16/geen-tijd-verliezen-van-opvang-naar-integratie-van-asielmigranten", "lokaal_pad": ""}, "page": 3}]}, {"type": "h2", "text": "Integratie als langetermijnproces", "citations": []}, {"type": "p", "text": "De WRR onderzocht in 2015 de integratie van asielmigranten en concludeert dat integratie een langetermijnproces is dat zich over generaties uitstrekt. Succesvolle integratie vraagt om investeringen in taal, onderwijs, werk en sociale netwerken, en om een overheid die consistent beleid voert.", "citations": [{"source_id": {"instituut": "WRR", "titel": "Geen tijd verliezen: van opvang naar integratie van asielmigranten", "jaar": "2015", "auteur": "WRR", "url": "https://www.wrr.nl/documenten/2015/12/16/geen-tijd-verliezen-van-opvang-naar-integratie-van-asielmigranten", "lokaal_pad": ""}, "page": 5}]}, {"type": "h2", "text": "Arbeidsmigratie", "citations": []}, {"type": "p", "text": "De SER adviseerde in 2015 over arbeidsmigratie en de effecten op de arbeidsmarkt. Arbeidsmigratie draagt bij aan economische groei, maar vraagt om waarborgen voor arbeidsvoorwaarden, huisvesting en sociale voorzieningen om negatieve effecten op de brede welvaart te voorkomen.", "citations": [{"source_id": {"instituut": "SER", "titel": "Arbeidsmigratie", "jaar": "2015", "auteur": "SER", "url": "https://www.ser.nl/-/media/ser/downloads/kabinetsreacties/2015-arbeidsmigratie.pdf", "lokaal_pad": ""}, "page": 4}]}, {"type": "h2", "text": "Diversiteit en sociale cohesie", "citations": []}, {"type": "p", "text": "Het SCP onderzoekt hoe etnische en culturele diversiteit zich verhoudt tot sociale cohesie. De uitkomsten zijn genuanceerd: diversiteit kan leiden tot meer onderling begrip, maar ook tot spanningen als groepen langs elkaar heen leven. Beleid dat ontmoeting en uitwisseling stimuleert kan beide kanten versterken.", "citations": [{"source_id": {"instituut": "SCP", "titel": "Verschil in Nederland 2014-2020", "jaar": "2014", "auteur": "SCP", "url": "https://repository.scp.nl/?atabase=9eb0b28e-b2b1-44e2-85dd-53a0f04eef34", "lokaal_pad": ""}, "page": 8}]}, {"type": "h2", "text": "Provinciale rol", "citations": []}, {"type": "p", "text": "Voor de provincie Utrecht, met haar groeiende en diverse bevolking, liggen er opgaven op het gebied van wonen, onderwijs, arbeidsmarkt en sociale voorzieningen die raken aan migratie en integratie. Een [[sociale-cohesie:inclusieve samenleving]] vraagt om beleid dat oog heeft voor zowel nieuwkomers als bestaande inwoners.", "citations": [{"source_id": {"instituut": "CPB", "titel": "Verzekeren tegen ziekte en arbeidsongeschiktheid", "jaar": "2015", "auteur": "", "url": "https://www.cpb.nl/publicatie/verzekeren-tegen-ziekte-en-arbeidsongeschiktheid"}}]}], "see_also": ["sociale-cohesie", "polarisatie-onbehagen", "burgerparticipatie"], "tags": []}, {"id": "burgerparticipatie", "title": "Burgerparticipatie en democratische vernieuwing", "thema": "verbonden-samenleving", "cluster": "4. Participatie", "meta": "Bronnen: CPB (5 documenten uit het beleidscorpus)", "sections": [{"type": "h2", "text": "Burgerparticipatie in Nederland", "citations": []}, {"type": "p", "text": "Burgerparticipatie — de betrokkenheid van burgers bij besluitvorming en beleid — is een belangrijk thema in de verbonden samenleving. Het SCP volgt via de Burgerperspectieven Berichten hoe burgers denken over hun rol in de samenleving en over de overheid.", "citations": [{"source_id": {"instituut": "SCP", "titel": "Burgerperspectieven Bericht 1 2026 - Thema Brede Welvaart", "jaar": "2026", "auteur": "SCP", "url": "https://www.scp.nl/documenten/2026/02/05/burgerperspectieven-bericht-1-2026-thema-brede-welvaart", "lokaal_pad": ""}, "page": 3}]}, {"type": "h2", "text": "Nieuwe vormen van participatie", "citations": []}, {"type": "p", "text": "Naast traditionele participatie via verkiezingen en inspraakavonden ontstaan nieuwe vormen: burgerberaden, thematische panels, online raadplegingen en co-creatietrajecten. De WRR onderzocht hoe deze nieuwe vormen bijdragen aan de kwaliteit van de democratie.", "citations": [{"source_id": {"instituut": "WRR", "titel": "Kwetsbaarheid en veerkracht", "jaar": "2020", "auteur": "WRR", "url": "https://www.wrr.nl/documenten/2020/06/16/kwetsbaarheid-en-veerkracht", "lokaal_pad": ""}, "page": 6}]}, {"type": "h2", "text": "Vertrouwen en participatie", "citations": []}, {"type": "p", "text": "Er is een wisselwerking tussen vertrouwen in instituties en participatie. Burgers die vertrouwen hebben in de overheid zijn eerder geneigd om te participeren. Omgekeerd kan participatie het vertrouwen versterken als burgers ervaren dat hun inbreng serieus wordt genomen.", "citations": [{"source_id": {"instituut": "ROB", "titel": "Bouwen aan vertrouwen in het openbaar bestuur", "jaar": "2006", "auteur": "ROB", "url": "https://www.raadopenbaarbestuur.nl/documenten/2006/12/18/bouwen-aan-vertrouwen-in-het-openbaar-bestuur", "lokaal_pad": ""}, "page": 4}]}, {"type": "h2", "text": "Beleidsimplicaties voor Utrecht", "citations": []}, {"type": "p", "text": "De provincie Utrecht experimenteert met vormen van burgerparticipatie in het provinciaal beleid. Dit sluit aan bij de bredere beweging richting een [[sociale-cohesie:meer verbonden samenleving]], waarin burgers niet alleen als ontvangers van beleid worden gezien, maar als mede-ontwerpers.", "citations": [{"source_id": {"instituut": "CPB", "titel": "Hoe gemeenten in de praktijk met hun geld omgaan: inzichten uit een reeks interviews", "jaar": "2015", "auteur": "", "url": "https://www.cpb.nl/publicatie/hoe-gemeenten-de-praktijk-met-hun-geld-omgaan-inzichten-uit-een-reeks-interviews"}}]}], "see_also": ["sociale-cohesie", "polarisatie-onbehagen"], "tags": []}, {"id": "bevolkingsontwikkeling", "title": "Bevolkingsontwikkeling en demografische prognoses", "thema": "demografie", "cluster": "1. Bevolkingsontwikkeling", "meta": "Bronnen: CPB (5 documenten uit het beleidscorpus)", "sections": [{"type": "h2", "text": "Demografische ontwikkelingen in Nederland", "citations": []}, {"type": "p", "text": "Nederland vergrijst, maar groeit ook: de bevolking neemt toe door migratie en een positief geboortesaldo, terwijl het aandeel ouderen gestaag stijgt. Het PBL en CBS maken gezamenlijk regionale bevolkings- en huishoudensprognoses die de basis vormen voor ruimtelijk beleid, woningbouwprogrammering en voorzieningenplanning.", "citations": [{"source_id": {"instituut": "PBL", "titel": "Cahier Demografie, toekomstverkenning WLO", "jaar": "2015", "auteur": "PBL", "url": "https://www.pbl.nl/publicaties/cahier-demografie-toekomstverkenning-welvaart-en-leefomgeving", "lokaal_pad": ""}, "page": 3}]}, {"type": "p", "text": "Uit de Welvaart en Leefomgeving-verkenning van het PBL uit 2015 blijkt dat de demografische ontwikkeling per regio sterk verschilt. Waar de Randstad en de provincie Utrecht groeien, krimpen regio's als Limburg en Oost-Groningen. Deze regionale verschillen in bevolkingsontwikkeling hebben grote gevolgen voor woningmarkten, voorzieningen en de leefomgeving.", "citations": [{"source_id": {"instituut": "PBL", "titel": "Cahier Demografie, toekomstverkenning WLO", "jaar": "2015", "auteur": "PBL", "url": "https://www.pbl.nl/publicaties/cahier-demografie-toekomstverkenning-welvaart-en-leefomgeving", "lokaal_pad": ""}, "page": 5}]}, {"type": "h2", "text": "Vergrijzing en ontgroening", "citations": []}, {"type": "p", "text": "De vergrijzing is een van de meest ingrijpende demografische trends. De WRR onderzocht in 2024 de gevolgen van Europese vergrijzing voor pensioenen en begrotingshoudbaarheid. Een krimpend arbeidsaanbod en stijgende zorgkosten leggen een steeds grotere claim op de welvaart van jongere generaties. Tegelijkertijd neemt het aandeel jongeren in de totale bevolking af (ontgroening), wat gevolgen heeft voor onderwijs, arbeidsmarkt en woningmarkt.", "citations": [{"source_id": {"instituut": "WRR", "titel": "Europese vergrijzing in het vizier", "jaar": "2024", "auteur": "WRR", "url": "https://www.wrr.nl/documenten/2024/09/25/europese-vergrijzing-in-het-vizier", "lokaal_pad": ""}, "page": 4}]}, {"type": "h2", "text": "Regionale verschillen", "citations": []}, {"type": "p", "text": "De ROB adviseerde al in 2008 over bevolkingsdaling in krimpregio's. Waar sommige regio's kampen met leegstand, vergrijzing en een krimpend voorzieningenniveau, staan andere regio's onder druk door snelle bevolkingsgroei, woningtekort en infrastructurele knelpunten. Het CPB analyseerde de effecten van demografische ontwikkelingen op de houdbaarheid van de overheidsfinanciën.", "citations": [{"source_id": {"instituut": "ROB", "titel": "Adviesrapport Bevolkingsdaling", "jaar": "2008", "auteur": "ROB", "url": "https://www.raadopenbaarbestuur.nl/documenten/2008/03/31/bevolkingsdaling", "lokaal_pad": ""}, "page": 4}, {"source_id": {"instituut": "CPB", "titel": "Een model voor meerdere pensioenrisico's", "jaar": "2015", "auteur": "CPB", "url": "https://www.cpb.nl/publicatie/een-model-voor-meerdere-pensioenrisicos", "lokaal_pad": ""}, "page": 3}]}, {"type": "h2", "text": "Gevolgen voor Utrecht", "citations": []}, {"type": "p", "text": "De provincie Utrecht is een van de snelst groeiende regio's van Nederland. Dit biedt economische kansen, maar legt ook druk op de woningmarkt, de bereikbaarheid, het milieu en de sociale voorzieningen. Een evenwichtig demografisch beleid vraagt om een [[toekomstbehendigheid:toekomstbestendige]] inrichting van de provincie.", "citations": [{"source_id": {"instituut": "CPB", "titel": "Een model voor meerdere pensioenrisico’s", "jaar": "2015", "auteur": "", "url": "https://www.cpb.nl/publicatie/een-model-voor-meerdere-pensioenrisicos"}}]}], "see_also": ["vergrijzing-zorg", "krimp-demografie"], "tags": []}, {"id": "vergrijzing-zorg", "title": "Vergrijzing, zorg en arbeidsmarkt", "thema": "demografie", "cluster": "2. Vergrijzing", "meta": "Bronnen: CPB (5 documenten uit het beleidscorpus)", "sections": [{"type": "h2", "text": "Vergrijzing als maatschappelijke opgave", "citations": []}, {"type": "p", "text": "De vergrijzing van de Nederlandse bevolking heeft ingrijpende gevolgen voor de zorg, de arbeidsmarkt en de sociale zekerheid. Het aantal 65-plussers stijgt van 3,5 miljoen in 2024 naar naar verwachting 4,7 miljoen in 2040, terwijl de beroepsbevolking krimpt.", "citations": [{"source_id": {"instituut": "WRR", "titel": "Europese vergrijzing in het vizier", "jaar": "2024", "auteur": "WRR", "url": "https://www.wrr.nl/documenten/2024/09/25/europese-vergrijzing-in-het-vizier", "lokaal_pad": ""}, "page": 4}]}, {"type": "h2", "text": "Zorg en vergrijzing", "citations": []}, {"type": "p", "text": "De SER identificeerde in 2022 zeven obstakels in de ouderenzorg: het tekort aan zorgpersoneel, de groeiende zorgvraag, de complexiteit van de zorgorganisatie, de financiering, de kwaliteit van zorg, de positie van de mantelzorger en de samenhang tussen wonen, welzijn en zorg. Het RIVM schetst in de Volksgezondheid Toekomst Verkenning de effecten van vergrijzing op de zorgvraag.", "citations": [{"source_id": {"instituut": "SER", "titel": "7 obstakels in de ouderenzorg", "jaar": "2022", "auteur": "SER", "url": "https://www.ser.nl/nl/publicaties/obstakels-ouderenzorg", "lokaal_pad": ""}, "page": 4}, {"source_id": {"instituut": "RIVM", "titel": "Volksgezondheid Toekomst Verkenning 2018", "jaar": "2018", "auteur": "RIVM", "url": "https://www.rivm.nl/publicaties/volksgezondheid-toekomst-verkenning-2018-gezond-vooruitzicht-synthese", "lokaal_pad": ""}, "page": 3}]}, {"type": "h2", "text": "Arbeidsmarkt", "citations": []}, {"type": "p", "text": "Een krimpend arbeidsaanbod door vergrijzing heeft gevolgen voor vrijwel alle sectoren. Het CPB analyseerde de effecten op pensioenen, de arbeidsparticipatie van ouderen en de houdbaarheid van de sociale zekerheid. Het SCP onderzocht hoe vitale ouderen kunnen bijdragen aan de samenleving via vrijwilligerswerk en informele zorg.", "citations": [{"source_id": {"instituut": "CPB", "titel": "Een model voor meerdere pensioenrisico's", "jaar": "2015", "auteur": "CPB", "url": "https://www.cpb.nl/publicatie/een-model-voor-meerdere-pensioenrisicos", "lokaal_pad": ""}, "page": 5}, {"source_id": {"instituut": "SCP", "titel": "Investeren in vitale ouderen", "jaar": "2024", "auteur": "SCP", "url": "https://repository.scp.nl/?atabase=9eb0af67-a0d0-4e96-9dfc-116f1a04742e", "lokaal_pad": ""}, "page": 3}]}, {"type": "h2", "text": "Provinciaal beleid", "citations": []}, {"type": "p", "text": "Voor de provincie Utrecht betekent de vergrijzing dat investeringen in woningaanpassing, zorginfrastructuur, vervoer en mantelzorgondersteuning nodig zijn om de kwaliteit van leven van een groeiende groep ouderen te waarborgen.", "citations": [{"source_id": {"instituut": "CPB", "titel": "Advies Technische Werkgroep methodiek MLT-Zorg", "jaar": "2015", "auteur": "", "url": "https://www.cpb.nl/publicatie/advies-technische-werkgroep-methodiek-mlt-zorg"}}]}], "see_also": ["bevolkingsontwikkeling", "krimp-demografie"], "tags": []}, {"id": "krimp-demografie", "title": "Krimpregio's en demografische transitie", "thema": "demografie", "cluster": "3. Krimp en regionale demografie", "meta": "Bronnen: CPB (5 documenten uit het beleidscorpus)", "sections": [{"type": "h2", "text": "Krimpregio's in Nederland", "citations": []}, {"type": "p", "text": "Niet alle regio's in Nederland groeien. In Limburg, Oost-Groningen en delen van Zeeland neemt de bevolking af. De ROB adviseerde al in 2008 over de gevolgen van bevolkingsdaling en de noodzaak van een actief beleid om de leefbaarheid in krimpregio's te behouden.", "citations": [{"source_id": {"instituut": "ROB", "titel": "Adviesrapport Bevolkingsdaling", "jaar": "2008", "auteur": "ROB", "url": "https://www.raadopenbaarbestuur.nl/documenten/2008/03/31/bevolkingsdaling", "lokaal_pad": ""}, "page": 3}]}, {"type": "h2", "text": "Gevolgen voor voorzieningen", "citations": []}, {"type": "p", "text": "Het KiM onderzocht in 2019 de effecten van bevolkingsdaling op bereikbaarheid en mobiliteit. In krimpregio's staan voorzieningen zoals openbaar vervoer, scholen, winkels en zorg onder druk door een afnemend draagvlak. Dit kan leiden tot een neerwaartse spiraal: minder voorzieningen versnellen de vertrek uit de regio.", "citations": [{"source_id": {"instituut": "KiM", "titel": "Bevolkingsdaling en effecten op bereikbaarheid en mobiliteit", "jaar": "2019", "auteur": "KiM", "url": "https://www.kimnet.nl/documenten/2019/01/28/bevolkingsdaling-en-de-effecten-op-de-bereikbaarheid-en-de-mobiliteit-in-nederland", "lokaal_pad": ""}, "page": 4}]}, {"type": "h2", "text": "Demografische transitie", "citations": []}, {"type": "p", "text": "Het PBL plaatst de regionale bevolkingsontwikkeling in het bredere kader van de demografische transitie: de overgang van hoge naar lage geboorte- en sterftecijfers die alle ontwikkelde landen doormaken. De timing en snelheid van deze transitie verschilt per regio, met uiteenlopende gevolgen voor de ruimtelijke ordening.", "citations": [{"source_id": {"instituut": "PBL", "titel": "Cahier Demografie, toekomstverkenning WLO", "jaar": "2015", "auteur": "PBL", "url": "https://www.pbl.nl/publicaties/cahier-demografie-toekomstverkenning-welvaart-en-leefomgeving", "lokaal_pad": ""}, "page": 6}]}, {"type": "h2", "text": "Beleidsopgaven", "citations": []}, {"type": "p", "text": "Het CPB analyseerde de economische gevolgen van krimp voor de woningmarkt, de arbeidsmarkt en de overheidsfinanciën. Beleid in krimpregio's moet zich richten op het behoud van basisvoorzieningen, het stimuleren van innovatie en het accommoderen van krimp, in plaats van deze te willen keren.", "citations": [{"source_id": {"instituut": "CPB", "titel": "Het sturende effect van een algemene uitkering op het gemeentelijke aanbod van huishoudelijke verzorging", "jaar": "2015", "auteur": "", "url": "https://www.cpb.nl/publicatie/het-sturende-effect-van-een-algemene-uitkering-op-het-gemeentelijke-aanbod-van-huishoudelijke-verzorging"}}]}], "see_also": ["bevolkingsontwikkeling", "vergrijzing-zorg"], "tags": []}, {"id": "ai-samenleving", "title": "AI en digitalisering: impact op de samenleving", "thema": "ai-digitalisering", "cluster": "1. AI en samenleving", "meta": "Bronnen: CPB (5 documenten uit het beleidscorpus)", "sections": [{"type": "h2", "text": "Digitalisering als maatschappelijke transitie", "citations": []}, {"type": "p", "text": "Digitalisering is een van de meest ingrijpende maatschappelijke transities van de 21e eeuw. De WRR-wees in 2015 in het rapport Big Data in een vrije en veilige samenleving op de fundamentele spanning tussen de kansen van datagedreven innovatie en de risico's voor privacy, autonomie en sociale gelijkheid. Het Rathenau Instituut onderzocht hoe de datagedreven samenleving de verhouding tussen burgers, overheid en bedrijven verandert.", "citations": [{"source_id": {"instituut": "WRR", "titel": "Big Data in een vrije en veilige samenleving", "jaar": "2016", "auteur": "WRR", "url": "https://www.wrr.nl/documenten/2016/04/28/big-data-in-een-vrije-en-veilige-samenleving", "lokaal_pad": ""}, "page": 4}, {"source_id": {"instituut": "Rathenau", "titel": "De datagedreven samenleving", "jaar": "2015", "auteur": "Rathenau", "url": "https://www.rathenau.nl/nl/digitalisering/de-datagedreven-samenleving", "lokaal_pad": ""}, "page": 3}]}, {"type": "h2", "text": "AI, werk en onderwijs", "citations": []}, {"type": "p", "text": "De inzet van kunstmatige intelligentie verandert de arbeidsmarkt fundamenteel. Het CPB onderzocht de risico's van cyberveiligheid voor de economie, terwijl de Onderwijsraad in 2017 adviseerde over de gevolgen van digitalisering voor het onderwijs. Niet alleen de inhoud van banen verandert, maar ook de manier waarop mensen leren en zich ontwikkelen.", "citations": [{"source_id": {"instituut": "CPB", "titel": "Risicorapportage Cyberveiligheid Economie", "jaar": "2017", "auteur": "CPB", "url": "https://www.cpb.nl/publicatie/risicorapportage-cyberveiligheid-economie", "lokaal_pad": ""}, "page": 3}, {"source_id": {"instituut": "Onderwijsraad", "titel": "Doordacht digitaal", "jaar": "2017", "auteur": "Onderwijsraad", "url": "https://www.onderwijsraad.nl/documenten/2017/05/09/doordacht-digitaal", "lokaal_pad": ""}, "page": 4}]}, {"type": "h2", "text": "Algoritmes en discriminatie", "citations": []}, {"type": "p", "text": "De SER onderzocht in 2022 het gebruik van algoritmes bij werving en selectie en de risico's op discriminatie en uitsluiting. Het Rathenau Instituut waarschuwde dat datagedreven besluitvorming onbedoeld bestaande ongelijkheden kan versterken als de onderliggende data bias bevatten.", "citations": [{"source_id": {"instituut": "SER", "titel": "Onderzoek algoritmegebruik en risico's op discriminatie", "jaar": "2022", "auteur": "SER", "url": "https://www.ser.nl/-/media/ser/downloads/thema/digitalisering/2022-06-10-presentatie-digiq.pdf", "lokaal_pad": ""}, "page": 4}, {"source_id": {"instituut": "Rathenau", "titel": "Berekende risico's - verzekeren in datagedreven samenleving", "jaar": "2015", "auteur": "Rathenau", "url": "https://www.rathenau.nl/nl/digitalisering/berekende-risicos-verzekeren-de-datagedreven-samenleving", "lokaal_pad": ""}, "page": 5}]}, {"type": "h2", "text": "Digitalisering van de publieke sector", "citations": []}, {"type": "p", "text": "De ROB besprak in 2018 de impact van digitalisering op de democratische besluitvorming en de kwaliteit van het openbaar bestuur. De vraag is hoe digitale technologie kan worden ingezet om publieke dienstverlening te verbeteren, zonder dat dit ten koste gaat van privacy, gelijkheid of menselijke maat.", "citations": [{"source_id": {"instituut": "ROB", "titel": "Democratie en digitalisering", "jaar": "2018", "auteur": "ROB", "url": "https://www.raadopenbaarbestuur.nl/documenten/2018/06/19/verslag-bijeenkomst-democratie-en-digitalisering", "lokaal_pad": ""}, "page": 3}]}, {"type": "h2", "text": "Digitale inclusie", "citations": []}, {"type": "p", "text": "Digitalisering dreigt een kloof te creëren tussen wie wel en niet mee kan komen in de digitale samenleving. Het KiM onderzocht de impact van digitalisering op toegang tot vervoersdiensten, waaruit blijkt dat kwetsbare groepen het risico lopen buitengesloten te worden naarmate diensten digitaliseren. Digitale inclusie is daarmee een voorwaarde voor een [[sociale-cohesie:verbonden samenleving]].", "citations": [{"source_id": {"instituut": "KiM", "titel": "Impact van digitalisering op toegang tot vervoersdiensten", "jaar": "2020", "auteur": "KiM", "url": "https://www.kimnet.nl/documenten/2020/06/29/de-impact-van-digitalisering-op-de-toegang-tot-vervoersdiensten-een-literatuurreview", "lokaal_pad": ""}, "page": 4}]}], "see_also": ["ethiek-algoritmes", "digitale-overheid"], "tags": []}, {"id": "ethiek-algoritmes", "title": "Ethiek, algoritmes en digitale grondrechten", "thema": "ai-digitalisering", "cluster": "2. Ethiek en recht", "meta": "Bronnen: CPB (5 documenten uit het beleidscorpus)", "sections": [{"type": "h2", "text": "Ethische vraagstukken van AI", "citations": []}, {"type": "p", "text": "De inzet van kunstmatige intelligentie roept fundamentele ethische vragen op. Het Rathenau Instituut onderzocht hoe algoritmes beslissingen nemen die voorheen aan mensen waren voorbehouden, van gezichtsherkenning tot kredietscores. Wie is verantwoordelijk als een algoritme een verkeerde beslissing neemt?", "citations": [{"source_id": {"instituut": "Rathenau", "titel": "Berekende risico's - verzekeren in datagedreven samenleving", "jaar": "2015", "auteur": "Rathenau", "url": "https://www.rathenau.nl/nl/digitalisering/berekende-risicos-verzekeren-de-datagedreven-samenleving", "lokaal_pad": ""}, "page": 3}]}, {"type": "h2", "text": "Privacy en autonomie", "citations": []}, {"type": "p", "text": "De WRR waarschuwde in 2016 dat Big Data de privacy en autonomie van burgers onder druk zet. In een datagedreven samenleving worden steeds meer persoonlijke gegevens verzameld, geanalyseerd en gebruikt voor besluitvorming, vaak zonder dat burgers hier controle over hebben. De WRR pleit voor een herbezinning op de verhouding tussen veiligheid, economische belangen en grondrechten.", "citations": [{"source_id": {"instituut": "WRR", "titel": "Big Data in een vrije en veilige samenleving", "jaar": "2016", "auteur": "WRR", "url": "https://www.wrr.nl/documenten/2016/04/28/big-data-in-een-vrije-en-veilige-samenleving", "lokaal_pad": ""}, "page": 6}]}, {"type": "h2", "text": "Algoritmeregisters en toezicht", "citations": []}, {"type": "p", "text": "De overheid experimenteert met algoritmeregisters om transparantie te bieden over het gebruik van algoritmes in de publieke sector. De ROB adviseert dat digitalisering van de overheid gepaard moet gaan met waarborgen voor democratische controle en rechtsbescherming.", "citations": [{"source_id": {"instituut": "ROB", "titel": "Democratie en digitalisering", "jaar": "2018", "auteur": "ROB", "url": "https://www.raadopenbaarbestuur.nl/documenten/2018/06/19/verslag-bijeenkomst-democratie-en-digitalisering", "lokaal_pad": ""}, "page": 4}]}, {"type": "h2", "text": "Internationale regulering", "citations": []}, {"type": "p", "text": "De EU AI Act is het eerste omvattende juridische kader voor kunstmatige intelligentie ter wereld. De verordening classificeert AI-toepassingen op risico en stelt eisen aan transparantie, menselijk toezicht en aansprakelijkheid.", "citations": [{"source_id": {"instituut": "WRR", "titel": "The Public core of the Internet", "jaar": "2015", "auteur": "WRR", "url": "https://www.wrr.nl/documenten/2015/04/10/the-public-core-of-the-internet", "lokaal_pad": ""}, "page": 5}]}], "see_also": ["ai-samenleving", "digitale-overheid"], "tags": []}, {"id": "digitale-overheid", "title": "Digitalisering van de overheid en publieke dienstverlening", "thema": "ai-digitalisering", "cluster": "3. Digitale overheid", "meta": "Bronnen: CPB (5 documenten uit het beleidscorpus)", "sections": [{"type": "h2", "text": "Digitale overheid in Nederland", "citations": []}, {"type": "p", "text": "De Nederlandse overheid zet steeds meer in op digitalisering van publieke dienstverlening. Het Rathenau Instituut onderzocht de veiligheid van systemen voor de digitale overheid en de risico's van grote dataconcentraties. De ROB adviseerde over de democratische implicaties van digitalisering van het procesrecht.", "citations": [{"source_id": {"instituut": "Rathenau", "titel": "Veiligheid van systemen voor de digitale overheid", "jaar": "2013", "auteur": "Rathenau", "url": "https://www.rathenau.nl/nl/digitalisering/veiligheid-van-systemen-voor-de-digitale-overheid", "lokaal_pad": ""}, "page": 3}, {"source_id": {"instituut": "ROB", "titel": "Democratie en digitalisering", "jaar": "2018", "auteur": "ROB", "url": "https://www.raadopenbaarbestuur.nl/documenten/2018/06/19/verslag-bijeenkomst-democratie-en-digitalisering", "lokaal_pad": ""}, "page": 4}]}, {"type": "h2", "text": "Marktordening en ICT", "citations": []}, {"type": "p", "text": "Het CPB onderzocht in 2016 de marktordening bij nieuwe ICT-toepassingen en de gevolgen voor concurrentie en innovatie. De overheid moet voorkomen dat afhankelijkheid van enkele grote technologiebedrijven de publieke belangen ondermijnt.", "citations": [{"source_id": {"instituut": "CPB", "titel": "Marktordening bij nieuwe ICT-toepassingen", "jaar": "2016", "auteur": "CPB", "url": "https://www.cpb.nl/publicatie/marktordening-bij-nieuwe-ict-toepassingen", "lokaal_pad": ""}, "page": 3}]}, {"type": "h2", "text": "Toegankelijkheid en inclusie", "citations": []}, {"type": "p", "text": "Digitalisering van de overheid mag niet leiden tot uitsluiting van burgers die geen toegang hebben tot digitale middelen of vaardigheden. De WRR adviseert dat de overheid bij digitalisering oog moet houden voor de menselijke maat en alternatieve kanalen moet blijven bieden.", "citations": [{"source_id": {"instituut": "WRR", "titel": "Big Data in een vrije en veilige samenleving", "jaar": "2016", "auteur": "WRR", "url": "https://www.wrr.nl/documenten/2016/04/28/big-data-in-een-vrije-en-veilige-samenleving", "lokaal_pad": ""}, "page": 8}]}], "see_also": ["ai-samenleving", "ethiek-algoritmes"], "tags": []}, {"id": "transities-beleid", "title": "Transities en transitiemanagement in beleid", "thema": "toekomstbehendigheid", "cluster": "1. Transities", "meta": "Bronnen: CPB (5 documenten uit het beleidscorpus)", "sections": [{"type": "h2", "text": "Wat zijn transities?", "citations": []}, {"type": "p", "text": "Transities zijn fundamentele, langdurige veranderingsprocessen waarin een maatschappelijk systeem van structuur verandert. Denk aan de energietransitie, de landbouwtransitie, de circulaire transitie of de mobiliteitstransitie. Kenmerkend is dat transities meerdere decennia beslaan, niet-lineair verlopen en gepaard gaan met onzekerheid en weerstand.", "citations": [{"source_id": {"instituut": "PBL", "titel": "Welvaart en Leefomgeving-verkenning (WLO)", "jaar": "2015", "auteur": "PBL", "url": "https://www.pbl.nl/publicaties/cahier-demografie-toekomstverkenning-welvaart-en-leefomgeving", "lokaal_pad": ""}, "page": 4}]}, {"type": "h2", "text": "Transitiemanagement", "citations": []}, {"type": "p", "text": "Het PBL ontwikkelde methoden voor transitiemanagement die in de Welvaart en Leefomgeving-verkenningen worden gebruikt. Centraal staat het idee dat transities niet centraal te plannen of te sturen zijn, maar dat de overheid wel condities kan scheppen voor verandering: door experimenten, door het wegnemen van barrières en door consistent langetermijnbeleid.", "citations": [{"source_id": {"instituut": "PBL", "titel": "Vier scenario's voor de inrichting van Nederland in 2050", "jaar": "2023", "auteur": "PBL", "url": "https://www.pbl.nl/publicaties/vier-scenarios-voor-de-inrichting-van-nederland-in-2050", "lokaal_pad": ""}, "page": 5}]}, {"type": "h2", "text": "Leren in transities", "citations": []}, {"type": "p", "text": "De ROB adviseerde in 2023 dat ruimte voor leren een essentiële voorwaarde is voor succesvolle transities. Beleid moet niet worden gezien als een eenmalig plan, maar als een continu proces van vallen, opstaan en weer doorgaan. De RLI onderzocht in 2022 hoe financieringsstructuren transities kunnen ondersteunen of belemmeren.", "citations": [{"source_id": {"instituut": "ROB", "titel": "Vallen, opstaan en weer doorgaan - ruimte voor leren in transities", "jaar": "2023", "auteur": "ROB", "url": "https://www.raadopenbaarbestuur.nl/documenten/2023/04/19/vallen-opstaan-en-weer-doorgaan", "lokaal_pad": ""}, "page": 4}, {"source_id": {"instituut": "RLI", "titel": "Financiering in transitie", "jaar": "2022", "auteur": "RLI", "url": "https://www.rli.nl/publicaties/2022/advies/financiering-in-transitie", "lokaal_pad": ""}, "page": 3}]}, {"type": "h2", "text": "Samenhang tussen transities", "citations": []}, {"type": "p", "text": "Transities hangen vaak samen. De energietransitie heeft gevolgen voor de woningmarkt, de mobiliteitstransitie voor de ruimtelijke ordening. Het KiM onderzocht de samenhang tussen transities in reispatronen. Een integrale aanpak die transities in samenhang beschouwt is effectiever dan sectoraal beleid.", "citations": [{"source_id": {"instituut": "KiM", "titel": "Transities tussen reispatronen", "jaar": "2016", "auteur": "KiM", "url": "https://www.kimnet.nl/documenten/2016/11/24/transities-tussen-reispatronen_latente-transitie-analyse-toegepast-binnen-het-mobility-biographies-framework", "lokaal_pad": ""}, "page": 3}]}, {"type": "h2", "text": "Provinciale rol", "citations": []}, {"type": "p", "text": "Provincies spelen een cruciale rol in transities via ruimtelijke ordening, vergunningverlening, subsidieprogramma's en regionale samenwerking. [[adaptief-bestuur:Adaptief bestuur]] is hierbij het sleutelconcept.", "citations": [{"source_id": {"instituut": "CPB", "titel": "Voorstel evaluatie kansspelbeleid", "jaar": "2015", "auteur": "", "url": "https://www.cpb.nl/publicatie/voorstel-evaluatie-kansspelbeleid"}}]}], "see_also": ["adaptief-bestuur", "toekomstverkenningen"], "tags": []}, {"id": "adaptief-bestuur", "title": "Adaptief bestuur, veerkracht en governance", "thema": "toekomstbehendigheid", "cluster": "2. Adaptief bestuur", "meta": "Bronnen: CPB (5 documenten uit het beleidscorpus)", "sections": [{"type": "h2", "text": "Adaptief bestuur in onzekere tijden", "citations": []}, {"type": "p", "text": "De WRR pleit in Kwetsbaarheid en veerkracht voor een overheid die niet alleen reageert op crises maar proactief anticipeert op toekomstige ontwikkelingen. Adaptief bestuur betekent dat beleid flexibel is, dat er geëxperimenteerd kan worden, en dat organisaties kunnen leren van fouten en tegenslagen.", "citations": [{"source_id": {"instituut": "WRR", "titel": "Kwetsbaarheid en veerkracht", "jaar": "2020", "auteur": "WRR", "url": "https://www.wrr.nl/documenten/2020/06/16/kwetsbaarheid-en-veerkracht", "lokaal_pad": ""}, "page": 4}]}, {"type": "h2", "text": "Veerkracht van de overheid", "citations": []}, {"type": "p", "text": "Veerkracht is het vermogen van een systeem om schokken op te vangen en zich aan te passen zonder zijn kernfuncties te verliezen. De WRR adviseert dat de overheid investeert in veerkracht door het verbreden van beleidsopties, het aanleggen van buffers en het versterken van adaptieve capaciteit.", "citations": [{"source_id": {"instituut": "WRR", "titel": "Kwetsbaarheid en veerkracht", "jaar": "2020", "auteur": "WRR", "url": "https://www.wrr.nl/documenten/2020/06/16/kwetsbaarheid-en-veerkracht", "lokaal_pad": ""}, "page": 6}]}, {"type": "h2", "text": "Governance van transities", "citations": []}, {"type": "p", "text": "De ROB onderzocht in 2017 de governance van gedecentraliseerde beleidsuitvoering. Transities vragen om nieuwe bestuurlijke verhoudingen tussen Rijk, provincies, gemeenten en maatschappelijke partijen. Dit betekent dat de overheid niet alleen stuurt maar ook faciliteert, verbindt en ruimte geeft.", "citations": [{"source_id": {"instituut": "ROB", "titel": "Governance van gedecentraliseerde beleidsuitvoering", "jaar": "2017", "auteur": "ROB", "url": "https://www.raadopenbaarbestuur.nl/documenten/2017/05/26/een-nieuw-speelveld-een-andere-opstelling", "lokaal_pad": ""}, "page": 4}]}, {"type": "h2", "text": "Financiële veerkracht", "citations": []}, {"type": "p", "text": "Het SER-advies over een toekomstbestendig pensioenstelsel en de RLI-adviezen over financiering in transitie laten zien dat financiële veerkracht een randvoorwaarde is voor adaptief bestuur. Zonder gezonde overheidsfinanciën en robuuste instituties is het moeilijk om te investeren in de toekomst.", "citations": [{"source_id": {"instituut": "SER", "titel": "Hoofdlijnen toekomstbestendig pensioenstelsel", "jaar": "2015", "auteur": "SER", "url": "https://www.ser.nl/-/media/ser/downloads/overige-publicaties/2015/hoofdlijnen-toekomstbestendig-pensioenstelsel.pdf", "lokaal_pad": ""}, "page": 3}, {"source_id": {"instituut": "RLI", "titel": "Financiering in transitie", "jaar": "2022", "auteur": "RLI", "url": "https://www.rli.nl/publicaties/2022/advies/financiering-in-transitie", "lokaal_pad": ""}, "page": 5}]}], "see_also": ["transities-beleid", "toekomstverkenningen"], "tags": []}, {"id": "toekomstverkenningen", "title": "Toekomstverkenningen en strategische beleidsvorming", "thema": "toekomstbehendigheid", "cluster": "3. Toekomstverkenningen", "meta": "Bronnen: CPB (5 documenten uit het beleidscorpus)", "sections": [{"type": "h2", "text": "Waarom toekomstverkenningen?", "citations": []}, {"type": "p", "text": "In een complexe en snel veranderende wereld is het niet mogelijk om de toekomst te voorspellen, maar wel om scenario's te ontwikkelen die helpen bij strategische besluitvorming. Het PBL maakt regelmatig toekomstverkenningen op het gebied van welvaart, leefomgeving, klimaat en energie.", "citations": [{"source_id": {"instituut": "PBL", "titel": "Welvaart en Leefomgeving-verkenning (WLO)", "jaar": "2015", "auteur": "PBL", "url": "https://www.pbl.nl/publicaties/cahier-demografie-toekomstverkenning-welvaart-en-leefomgeving", "lokaal_pad": ""}, "page": 3}]}, {"type": "h2", "text": "Scenariodenken", "citations": []}, {"type": "p", "text": "Het PBL ontwikkelde in 2023 vier scenario's voor de inrichting van Nederland in 2050, die variëren van regionale samenwerking tot internationale concurrentie. Scenario's helpen beleidsmakers om robuuste strategieën te ontwikkelen die in meerdere mogelijke toekomsten werken.", "citations": [{"source_id": {"instituut": "PBL", "titel": "Vier scenario's voor de inrichting van Nederland in 2050", "jaar": "2023", "auteur": "PBL", "url": "https://www.pbl.nl/publicaties/vier-scenarios-voor-de-inrichting-van-nederland-in-2050", "lokaal_pad": ""}, "page": 4}]}, {"type": "h2", "text": "Navigeren en anticiperen", "citations": []}, {"type": "p", "text": "De WRR adviseerde in 2021 samen met de KNAW dat de overheid meer moet investeren in anticiperend vermogen. Dit betekent het structureel verkennen van toekomstige ontwikkelingen, het identificeren van kantelpunten en het ontwikkelen van strategische opties.", "citations": [{"source_id": {"instituut": "WRR", "titel": "Navigeren en anticiperen in onzekere tijden", "jaar": "2021", "auteur": "WRR", "url": "https://www.wrr.nl/documenten/2021/09/02/navigeren-en-anticiperen-in-onzekere-tijden", "lokaal_pad": ""}, "page": 4}]}, {"type": "h2", "text": "Toepassing in provinciaal beleid", "citations": []}, {"type": "p", "text": "De strategische kennisagenda van de provincie Utrecht is een voorbeeld van hoe toekomstverkenningen kunnen worden gebruikt om provinciaal beleid richting te geven. [[transities-beleid:Transities]] vragen om een lange adem en consistent beleid dat verder reikt dan de gebruikelijke bestuursperiode.", "citations": [{"source_id": {"instituut": "CPB", "titel": "Het belastingramingsmodel TAXUS", "jaar": "2015", "auteur": "", "url": "https://www.cpb.nl/publicatie/het-belastingramingsmodel-taxus"}}]}], "see_also": ["transities-beleid", "adaptief-bestuur"], "tags": []}, {"id": "eu-beleid-regio", "title": "EU-beleid en de regio", "thema": "eu-internationaal", "cluster": "1. EU en regio", "meta": "Bronnen: CPB (5 documenten uit het beleidscorpus)", "sections": [{"type": "h2", "text": "Europa en regionale ontwikkeling", "citations": []}, {"type": "p", "text": "Europees beleid heeft een directe impact op provincies en regio's in Nederland. De RLI adviseerde in 2015 dat er meer ruimte moet komen voor de regio in Europees beleid. Het Europese cohesiebeleid, het landbouwbeleid (GLB), de staatssteunregels en de milieuwetgeving bepalen in belangrijke mate de beleidsruimte van provincies.", "citations": [{"source_id": {"instituut": "RLI", "titel": "Ruimte voor de regio in Europees beleid", "jaar": "2015", "auteur": "RLI", "url": "https://www.rli.nl/publicaties/2015/advies/ruimte-voor-de-regio-in-europees-beleid", "lokaal_pad": ""}, "page": 4}]}, {"type": "h2", "text": "Europese Green Deal en provincie", "citations": []}, {"type": "p", "text": "De Europese Green Deal heeft grote gevolgen voor provinciaal beleid op het gebied van klimaat, energie, landbouw en mobiliteit. Het PBL onderzocht de effecten van Europees klimaatbeleid op de Nederlandse leefomgeving. De SER pleitte in 2019 voor een fair Europa dat sociale en ecologische duurzaamheid combineert.", "citations": [{"source_id": {"instituut": "PBL", "titel": "Aanpassen aan klimaatverandering", "jaar": "2015", "auteur": "PBL", "url": "https://www.pbl.nl/publicaties/aanpassen-aan-klimaatverandering-kwetsbaarheden-zien-kansen-grijpen", "lokaal_pad": ""}, "page": 5}, {"source_id": {"instituut": "SER", "titel": "Prioriteiten voor een fair Europa", "jaar": "2019", "auteur": "SER", "url": "https://www.ser.nl/nl/publicaties/fair-europa", "lokaal_pad": ""}, "page": 4}]}, {"type": "h2", "text": "EU-subsidies en regionale ontwikkeling", "citations": []}, {"type": "p", "text": "Europese subsidies, zoals uit het Europees Fonds voor Regionale Ontwikkeling (EFRO), spelen een belangrijke rol in regionale ontwikkeling. Het CPB onderzocht de effecten van Europese financieringsstromen op de Nederlandse economie en de regionale verdeling van welvaart.", "citations": [{"source_id": {"instituut": "CPB", "titel": "De Nederlandse financieringsstructuur in perspectief", "jaar": "2015", "auteur": "CPB", "url": "https://www.cpb.nl/publicatie/de-nederlandse-financieringsstructuur-in-perspectief", "lokaal_pad": ""}, "page": 5}]}, {"type": "h2", "text": "Europees beleid en provinciale beleidsvrijheid", "citations": []}, {"type": "p", "text": "De ROB analyseerde de spanning tussen Europese integratie en nationale beleidsvrijheid. Voor de provincie Utrecht betekent dit dat Europees beleid zowel kansen biedt (subsidies, samenwerking) als beperkingen stelt (staatssteun, milieuregels). Een goede Europese oriëntatie is essentieel voor effectief provinciaal bestuur.", "citations": [{"source_id": {"instituut": "CPB", "titel": "Beleidsvarianten met Saffier-II", "jaar": "2015", "auteur": "", "url": "https://www.cpb.nl/publicatie/beleidsvarianten-met-saffier-ii"}}]}], "see_also": ["eu-defensie-veiligheid", "internationaal-economie"], "tags": []}, {"id": "eu-defensie-veiligheid", "title": "Internationale veiligheid, defensie en strategische autonomie", "thema": "eu-internationaal", "cluster": "2. Veiligheid en defensie", "meta": "Bronnen: CPB (5 documenten uit het beleidscorpus)", "sections": [{"type": "h2", "text": "Veiligheid in een veranderende wereldorde", "citations": []}, {"type": "p", "text": "De WRR pleitte in 2017 in Veiligheid in een wereld van verbindingen voor een strategische visie op het defensiebeleid. De internationale veiligheidssituatie is fundamenteel veranderd door de opkomst van nieuwe grootmachten, cyberdreigingen en hybride oorlogsvoering.", "citations": [{"source_id": {"instituut": "WRR", "titel": "Veiligheid in een wereld van verbindingen", "jaar": "2017", "auteur": "WRR", "url": "https://www.wrr.nl/documenten/2017/05/10/veiligheid-in-een-wereld-van-verbindingen", "lokaal_pad": ""}, "page": 4}]}, {"type": "h2", "text": "Strategische autonomie van Europa", "citations": []}, {"type": "p", "text": "Na de Russische inval in Oekraïne is het debat over strategische autonomie van de EU versneld. Dit heeft gevolgen voor defensie, energie, grondstoffen en technologie. Het PBL onderzocht de effecten van verminderde handelsafhankelijkheid op de Nederlandse economie en leefomgeving.", "citations": [{"source_id": {"instituut": "PBL", "titel": "Aanpassen aan klimaatverandering", "jaar": "2015", "auteur": "PBL", "url": "https://www.pbl.nl/publicaties/aanpassen-aan-klimaatverandering-kwetsbaarheden-zien-kansen-grijpen", "lokaal_pad": ""}, "page": 6}]}, {"type": "h2", "text": "Cyberveiligheid en digitale weerbaarheid", "citations": []}, {"type": "p", "text": "De WRR adviseert dat digitale weerbaarheid een integraal onderdeel moet zijn van het veiligheidsbeleid. De afhankelijkheid van digitale infrastructuur maakt Nederland kwetsbaar voor cyberaanvallen, die zowel economische als maatschappelijke schade kunnen veroorzaken.", "citations": [{"source_id": {"instituut": "WRR", "titel": "The Public core of the Internet", "jaar": "2015", "auteur": "WRR", "url": "https://www.wrr.nl/documenten/2015/04/10/the-public-core-of-the-internet", "lokaal_pad": ""}, "page": 4}]}, {"type": "h2", "text": "Gevolgen voor de provincie", "citations": []}, {"type": "p", "text": "Internationale veiligheidsontwikkelingen hebben ook lokale gevolgen: van opvang van vluchtelingen tot bescherming van vitale infrastructuur en voorbereiding op crisisomstandigheden. De provincie Utrecht speelt een rol in de regionale veiligheidsorganisatie en crisisbeheersing.", "citations": [{"source_id": {"instituut": "CPB", "titel": "Determinanten van internetveiligheid: een empirische analyse van DDoS aanvallen", "jaar": "2015", "auteur": "", "url": "https://www.cpb.nl/publicatie/determinanten-van-internetveiligheid-een-empirische-analyse-van-ddos-aanvallen"}}]}], "see_also": ["eu-beleid-regio", "internationaal-economie"], "tags": []}, {"id": "internationaal-economie", "title": "Internationale economie, handel en concurrentievermogen", "thema": "eu-internationaal", "cluster": "3. Economie en handel", "meta": "Bronnen: CPB (5 documenten uit het beleidscorpus)", "sections": [{"type": "h2", "text": "Nederland in de wereldeconomie", "citations": []}, {"type": "p", "text": "Nederland is een van de meest open economieën ter wereld, sterk afhankelijk van internationale handel, investeringen en samenwerking. Het CPB analyseert de effecten van internationale economische ontwikkelingen op de Nederlandse welvaart, van handelsconflicten tot wisselkoersschommelingen.", "citations": [{"source_id": {"instituut": "CPB", "titel": "De Nederlandse financieringsstructuur in perspectief", "jaar": "2015", "auteur": "CPB", "url": "https://www.cpb.nl/publicatie/de-nederlandse-financieringsstructuur-in-perspectief", "lokaal_pad": ""}, "page": 3}]}, {"type": "h2", "text": "Concurrentievermogen van Europa", "citations": []}, {"type": "p", "text": "De SER adviseert over de positie van Europa in de wereldeconomie. De prioriteiten voor een fair Europa omvatten het versterken van het concurrentievermogen, het beschermen van strategische sectoren en het borgen van sociale en ecologische duurzaamheid in handelsverdragen.", "citations": [{"source_id": {"instituut": "SER", "titel": "Prioriteiten voor een fair Europa", "jaar": "2019", "auteur": "SER", "url": "https://www.ser.nl/nl/publicaties/fair-europa", "lokaal_pad": ""}, "page": 5}]}, {"type": "h2", "text": "Grondstoffen en strategische autonomie", "citations": []}, {"type": "p", "text": "De afhankelijkheid van import van kritieke grondstoffen is een strategisch risico. Het PBL onderzocht de grondstoffenvoorziening van Nederland en de mogelijkheden voor circulaire economie om deze afhankelijkheid te verminderen. De WRR plaatst dit in het bredere kader van de geopolitieke ontwikkelingen.", "citations": [{"source_id": {"instituut": "PBL", "titel": "Aanpassen aan klimaatverandering", "jaar": "2015", "auteur": "PBL", "url": "https://www.pbl.nl/publicaties/aanpassen-aan-klimaatverandering-kwetsbaarheden-zien-kansen-grijpen", "lokaal_pad": ""}, "page": 7}]}, {"type": "h2", "text": "Provinciale impact", "citations": []}, {"type": "p", "text": "Internationale economische ontwikkelingen hebben directe gevolgen voor de provincie Utrecht, van de exportgerichte industrie tot de kennisinstellingen en de logistieke sector. [[eu-beleid-regio:Europees beleid]] biedt kansen voor regionale economische ontwikkeling.", "citations": [{"source_id": {"instituut": "CPB", "titel": "Een meer uniforme belasting van kapitaalinkomen", "jaar": "2015", "auteur": "", "url": "https://www.cpb.nl/publicatie/een-meer-uniforme-belasting-van-kapitaalinkomen"}}]}], "see_also": ["eu-beleid-regio", "eu-defensie-veiligheid"], "tags": []}], "article_index": {"brede-welvaart-concept": "Brede welvaart: concept, meting en het BBP", "regionale-brede-welvaart": "Regionale brede welvaart: van advies naar beleid", "bestaanszekerheid-sociaal": "Bestaanszekerheid en sociale kwaliteit", "sociaaleconomisch": "Sociaaleconomisch beleid, inkomen en arbeid", "sociale-ongelijkheid": "Sociale ongelijkheid en intergenerationele rechtvaardigheid", "gezondheid-natuur-milieu": "Gezondheid, natuur en milieu", "wonen-mobiliteit": "Wonen, mobiliteit en bereikbaarheid", "circulair-klimaat": "Circulaire economie, klimaat en duurzame ontwikkeling", "begroting-mkba": "Begrotingssystematiek, MKBA en monitoring", "bestuur-rechtvaardigheid": "Bestuur, politieke keuzes en rechtvaardigheid", "onderwijs-cultuur": "Onderwijs, cultuur, sport en vrije tijd", "internationaal-migratie": "Internationale vergelijking en migratie", "toekomstverkenningen": "Toekomstverkenningen en strategische beleidsvorming", "sociale-cohesie": "Sociale cohesie, vertrouwen en maatschappelijke betrokkenheid", "polarisatie-onbehagen": "Polarisatie en maatschappelijk onbehagen", "migratie-integratie": "Migratie, integratie en diversiteit", "burgerparticipatie": "Burgerparticipatie en democratische vernieuwing", "bevolkingsontwikkeling": "Bevolkingsontwikkeling en demografische prognoses", "vergrijzing-zorg": "Vergrijzing, zorg en arbeidsmarkt", "krimp-demografie": "Krimpregio's en demografische transitie", "ai-samenleving": "AI en digitalisering: impact op de samenleving", "ethiek-algoritmes": "Ethiek, algoritmes en digitale grondrechten", "digitale-overheid": "Digitalisering van de overheid en publieke dienstverlening", "transities-beleid": "Transities en transitiemanagement in beleid", "adaptief-bestuur": "Adaptief bestuur, veerkracht en governance", "eu-beleid-regio": "EU-beleid en de regio", "eu-defensie-veiligheid": "Internationale veiligheid, defensie en strategische autonomie", "internationaal-economie": "Internationale economie, handel en concurrentievermogen"}, "thema_index": {"kwaliteit-van-leven": ["brede-welvaart-concept", "regionale-brede-welvaart", "bestaanszekerheid-sociaal", "sociaaleconomisch", "sociale-ongelijkheid", "gezondheid-natuur-milieu", "wonen-mobiliteit", "circulair-klimaat", "begroting-mkba", "bestuur-rechtvaardigheid", "onderwijs-cultuur", "internationaal-migratie", "toekomstverkenningen"], "verbonden-samenleving": ["sociale-cohesie", "polarisatie-onbehagen", "migratie-integratie", "burgerparticipatie"], "demografie": ["bevolkingsontwikkeling", "vergrijzing-zorg", "krimp-demografie"], "ai-digitalisering": ["ai-samenleving", "ethiek-algoritmes", "digitale-overheid"], "toekomstbehendigheid": ["transities-beleid", "adaptief-bestuur", "toekomstverkenningen"], "eu-internationaal": ["eu-beleid-regio", "eu-defensie-veiligheid", "internationaal-economie"]}, "cross_links": {"brede-welvaart-concept": ["regionale-brede-welvaart", "bestaanszekerheid-sociaal", "circulair-klimaat"], "regionale-brede-welvaart": ["brede-welvaart-concept", "bestaanszekerheid-sociaal"], "bestaanszekerheid-sociaal": ["sociaaleconomisch", "sociale-ongelijkheid"], "sociaaleconomisch": ["sociale-ongelijkheid", "bestaanszekerheid-sociaal"], "sociale-ongelijkheid": ["sociaaleconomisch", "bestaanszekerheid-sociaal", "regionale-brede-welvaart"], "gezondheid-natuur-milieu": ["circulair-klimaat", "regionale-brede-welvaart", "sociale-ongelijkheid"], "wonen-mobiliteit": ["regionale-brede-welvaart", "gezondheid-natuur-milieu"], "circulair-klimaat": ["sociale-ongelijkheid", "gezondheid-natuur-milieu"], "begroting-mkba": ["brede-welvaart-concept", "sociaaleconomisch"], "bestuur-rechtvaardigheid": ["sociale-ongelijkheid", "regionale-brede-welvaart", "begroting-mkba"], "onderwijs-cultuur": ["gezondheid-natuur-milieu", "bestaanszekerheid-sociaal"], "internationaal-migratie": ["sociale-ongelijkheid", "bestaanszekerheid-sociaal"], "toekomstverkenningen": ["transities-beleid", "adaptief-bestuur"], "sociale-cohesie": ["polarisatie-onbehagen", "migratie-integratie", "burgerparticipatie"], "polarisatie-onbehagen": ["sociale-cohesie", "migratie-integratie", "burgerparticipatie"], "migratie-integratie": ["sociale-cohesie", "polarisatie-onbehagen", "burgerparticipatie"], "burgerparticipatie": ["sociale-cohesie", "polarisatie-onbehagen"], "bevolkingsontwikkeling": ["vergrijzing-zorg", "krimp-demografie"], "vergrijzing-zorg": ["bevolkingsontwikkeling", "krimp-demografie"], "krimp-demografie": ["bevolkingsontwikkeling", "vergrijzing-zorg"], "ai-samenleving": ["ethiek-algoritmes", "digitale-overheid"], "ethiek-algoritmes": ["ai-samenleving", "digitale-overheid"], "digitale-overheid": ["ai-samenleving", "ethiek-algoritmes"], "transities-beleid": ["adaptief-bestuur", "toekomstverkenningen"], "adaptief-bestuur": ["transities-beleid", "toekomstverkenningen"], "eu-beleid-regio": ["eu-defensie-veiligheid", "internationaal-economie"], "eu-defensie-veiligheid": ["eu-beleid-regio", "internationaal-economie"], "internationaal-economie": ["eu-beleid-regio", "eu-defensie-veiligheid"]}};